import React, { useState, useEffect, useRef } from 'react';
import { ScriptParts } from '../types';
import * as service from '../services/nonFaceReview2Service';
import ScriptSection from '../components/ScriptSection';
import ImageCard, { NONFACE_POSES } from '../components/ImageCard';

declare var JSZip: any;

const LAYOUT_OPTIONS = [
  "Cận cảnh sản phẩm + nỗi đau trong cuộc sống + trải nghiệm thực tế + giới thiệu chức năng + trường hợp sử dụng + CTA",
  "Câu chuyện chủ đề + mở hộp sản phẩm + đánh giá chi tiết + sử dụng thực tế + CTA",
  "Review chân thực + chia sẻ trải nghiệm người dùng + giới thiệu sản phẩm + CTA",
  "Chủ đề đời sống + đánh giá so sánh + điểm nổi bật + sử dụng sản phẩm trong nhiều trường hợp",
  "Nỗi đau khách hàng + nguyên nhân + giải pháp từ sản phẩm + uy tín thương hiệu + CTA",
  "Giới thiệu sản phẩm + nỗi đau + trải nghiệm thực tế + đánh giá so sánh + bằng chứng + CTA",
  "Chia sẻ chân thực + kiến thức ngành + giới thiệu chức năng + đặc điểm nổi bật + ưu đãi + CTA",
  "Thu hút đối tượng mục tiêu + câu hỏi từ góc độ người dùng + giải đáp + giới thiệu sản phẩm + ưu đãi + CTA",
  "Kết quả và đánh giá trước + nỗi đau trong cuộc sống + giới thiệu sản phẩm + ưu đãi + CTA",
  "Câu hỏi + giải pháp cho nỗi đau + đặc điểm nổi bật sản phẩm + đảm bảo từ nhiều góc độ + CTA",
  "Nỗi đau theo mùa/khu vực + giới thiệu sản phẩm + hoàn cảnh sử dụng + cảm nhận khi trải nghiệm + CTA",
  "Sở thích + giới thiệu sản phẩm + so sánh + giải thích về giá trị và hình thức + đảm bảo + CTA",
  "Xác định đối tượng mục tiêu + giới thiệu sản phẩm + hướng dẫn sử dụng + thử nghiệm và đánh giá + CTA",
  "Phản hồi của người dùng + kiến thức chuyên môn + nỗi đau + giới thiệu sản phẩm + ưu đãi + CTA",
  "Nỗi đau của khách hàng + giải pháp của sản phẩm + kết quả thực tế + CTA",
  "Câu chuyện thất bại + bài học rút ra + sản phẩm là giải pháp + CTA",
  "Đặt câu hỏi + kể chuyện + dẫn dắt + thuyết phục + đưa ra sản phẩm + khẳng định + CTA",
  "Câu chuyện hàng ngày + biến cố bất ngờ + loay hoay tìm cách giải quyết + gặp sản phẩm như cơ duyên + CTA",
  "Sai lầm phổ biến + tôi cũng vậy + hậu quả kéo dài + quyết định đổi hướng + sản phẩm xuất hiện + CTA",
  "Ước muốn + rào cản + thử nhiều cách vẫn thất bại + một lựa chọn khác biệt + đạt được điều mong muốn + CTA",
  "Hook mạnh + giới thiệu công năng + CTA"
];

const SCENE_COUNT_OPTIONS = Array.from({ length: 13 }, (_, i) => {
  const count = i + 3;
  const seconds = count * 8;
  return { count, label: `${count} cảnh - ${seconds}s` };
});

const VOICE_OPTIONS = [
  "Giọng Bắc 20-40 tuổi",
  "Giọng Nam 20-40 tuổi",
  "Giọng Bắc 50-60 tuổi",
  "Giọng Nam 50-60 tuổi",
  "Giọng Bắc 60-80 tuổi",
  "Giọng Nam 60-80 tuổi"
];

const ADDRESSING_OPTIONS = [
  "em - anh chị",
  "em - các bác",
  "tôi - các bạn",
  "tớ - các cậu",
  "mình - các bạn",
  "tao - mày",
  "tui - mấy bà",
  "tui - mấy ní",
  "tui - các bác",
  "tui - mấy ông",
  "mình - cả nhà",
  "mình - mọi người"
];

const NonFaceReviewModule2: React.FC = () => {
  const storageKey = "nonface_review_2_project_v1_stable";
  const [state, setState] = useState<any>({
    backgroundFile: null,
    backgroundPreviewUrl: null,
    handFile: null,
    handPreviewUrl: null,
    gender: 'Nữ',
    voice: 'Giọng Bắc 20-40 tuổi',
    addressing: '',
    targetAudience: '',
    imageStyle: 'Realistic',
    handVisibility: 'with_hand',
    sceneCount: 5,
    productFiles: [], 
    productPreviewUrls: [],
    productName: '',
    keyword: '',
    scriptNote: '', 
    visualNote: '',
    scriptLayout: '',
    isGeneratingScript: false,
    isRegeneratingPart: {},
    script: null,
    images: {},
    imagePrompts: {},
    videoPrompts: {}
  });

  const productInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);
  const handInputRef = useRef<HTMLInputElement>(null);
  const localJsonRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            productFiles: [],
            backgroundFile: null,
            handFile: null,
            isGeneratingScript: false,
            isRegeneratingPart: {}
          }));
        }
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isRegeneratingPart, productFiles, backgroundFile, handFile, images, ...persistentData } = state;
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: images[key]?.url?.startsWith('data:') ? images[key].url : '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) {}
  }, [state]);

  // --- IMPORT / EXPORT LOGIC ---

  const processImportData = async (importedData: any) => {
    if (!Array.isArray(importedData) || importedData.length === 0) return;
    window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 10, complete: false } }));

    try {
      const firstItem = importedData[0];
      const inputs = firstItem.inputs || {};
      const settings = inputs.settings || {};
      const media = inputs.inputMedia || {};

      const newState = {
        ...state,
        productName: inputs.productName || state.productName,
        keyword: inputs.keyword || state.keyword,
        targetAudience: inputs.targetAudience || state.targetAudience,
        visualNote: inputs.visualNote || state.visualNote,
        scriptNote: inputs.scriptNote || state.scriptNote,
        gender: settings.gender || state.gender,
        voice: settings.voice || state.voice,
        addressing: settings.addressing || state.addressing,
        imageStyle: settings.imageStyle || state.imageStyle,
        handVisibility: settings.handVisibility || 'with_hand',
        scriptLayout: settings.scriptLayout || state.scriptLayout,
        productPreviewUrls: media.productImages || [],
        backgroundPreviewUrl: media.backgroundImage || "",
        handPreviewUrl: media.handImage || "",
        sceneCount: importedData.length,
        script: {}, images: {}, videoPrompts: {}
      };

      for (let i = 0; i < importedData.length; i++) {
        const item = importedData[i];
        const key = `v${i + 1}`;
        const itemSettings = item.inputs?.settings || {};

        newState.script[key] = item.script || '';
        newState.images[key] = { 
          url: item.outputImage || '', 
          loading: false, 
          angle: itemSettings.angle || '', 
          pose: itemSettings.pose || '',
          customPrompt: '' 
        };
        newState.videoPrompts[key] = { 
          text: item.videoPrompt || '', 
          loading: false, 
          visible: !!item.videoPrompt 
        };

        const percent = Math.round(((i + 1) / importedData.length) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === importedData.length - 1 } }));
        await new Promise(r => setTimeout(r, 30));
      }
      setState(newState);
    } catch (e) {
      alert("Lỗi khi nạp dữ liệu JSON!");
    }
  };

  const handleExport = async () => {
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const exportData = activeKeys.map((key, index) => ({
      stt: index + 1,
      inputs: {
        productName: state.productName,
        keyword: state.keyword,
        targetAudience: state.targetAudience, 
        visualNote: state.visualNote,
        scriptNote: state.scriptNote, 
        inputMedia: {
          productImages: state.productPreviewUrls,
          backgroundImage: state.backgroundPreviewUrl,
          handImage: state.handPreviewUrl
        },
        settings: {
          gender: state.gender,
          voice: state.voice,
          addressing: state.addressing,
          imageStyle: state.imageStyle,
          handVisibility: state.handVisibility,
          scriptLayout: state.scriptLayout,
          angle: state.images[key]?.angle || '',
          pose: state.images[key]?.pose || ''
        }
      },
      script: state.script ? state.script[key] : '',
      outputImage: state.images[key]?.url || '',
      videoPrompt: state.videoPrompts[key]?.text || ''
    }));

    return exportData;
  };

  useEffect(() => {
    const onGlobalExport = async () => {
      const data = await handleExport();
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
        detail: { data, moduleName: 'Non_Face_2_Project' } 
      }));
    };
    const onGlobalImport = (e: any) => processImportData(e.detail);

    window.addEventListener('REQUEST_EXPORT_DATA', onGlobalExport);
    window.addEventListener('REQUEST_IMPORT_DATA', onGlobalImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', onGlobalExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', onGlobalImport);
    };
  }, [state]);

  const handleLocalExportJson = async () => {
    const data = await handleExport();
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `NonFace2_${state.productName || 'Project'}_${Date.now()}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  // --- ACTIONS ---

  const handleProductFilesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const selectedFiles = Array.from(e.target.files);
      const updatedFiles = [...state.productFiles, ...selectedFiles].slice(0, 3);
      const updatedUrls = updatedFiles.map(f => URL.createObjectURL(f));
      setState((prev: any) => ({ ...prev, productFiles: updatedFiles, productPreviewUrls: updatedUrls }));
    }
  };

  const handleGenerate = async () => {
    if (state.productFiles.length === 0 && state.productPreviewUrls.length === 0) return alert("Vui lòng tải ảnh sản phẩm.");
    if (!state.productName) return alert("Vui lòng nhập tên sản phẩm.");

    setState((prev: any) => ({ ...prev, isGeneratingScript: true }));
    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }

      let layoutToUse = state.scriptLayout;
      if (!layoutToUse) layoutToUse = LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateNonFaceScript(
        imageParts, state.productName, state.keyword, layoutToUse, 
        state.gender, state.voice, state.addressing, state.sceneCount, state.targetAudience
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse, isGeneratingScript: false }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, isGeneratingScript: false }));
    }
  };

  const handleRegenerateScriptPart = async (key: string) => {
    if (state.isGeneratingScript || state.isRegeneratingPart[key] || !state.script) return;
    setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: true } }));
    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }
      const newPartContent = await service.regenerateNonFaceScriptPart(
        imageParts, state.productName, state.keyword, key, state.script[key], state.script, state.gender, state.voice, state.addressing, state.targetAudience
      );
      setState((p: any) => ({ ...p, script: { ...p.script, [key]: newPartContent }, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } }));
    } catch (error) {
      setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } }));
    }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      let productParts = state.productFiles.length > 0 
        ? await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)))
        : state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));

      const bgRefPart = state.backgroundFile ? await service.fileToGenerativePart(state.backgroundFile) : 
                       (state.backgroundPreviewUrl?.startsWith('data:') ? { mimeType: 'image/png', data: state.backgroundPreviewUrl.split(',')[1] } : null);

      const handRefPart = state.handFile ? await service.fileToGenerativePart(state.handFile) : 
                       (state.handPreviewUrl?.startsWith('data:') ? { mimeType: 'image/png', data: state.handPreviewUrl.split(',')[1] } : null);

      const poseLabel = NONFACE_POSES.find(p => p.value === state.images[key]?.pose)?.label || "";

      const url = await service.generateNonFaceImage(
        productParts, handRefPart, state.productName, state.script[key], state.images[key]?.customPrompt,
        state.imageStyle, state.handVisibility, state.scriptNote, state.visualNote, bgRefPart, state.images[key]?.angle, poseLabel
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, videoPrompts: { ...prev.videoPrompts, [key]: { ...prev.videoPrompts[key], loading: true, visible: true } } }));
    try {
      let productImageData = state.productFiles[0] ? (await service.fileToGenerativePart(state.productFiles[0])).data : (state.productPreviewUrls[0]?.split(',')[1] || "");
      const prompt = await service.generateNonFaceVeoPrompt(
        state.productName, state.script[key], state.gender, state.voice, state.handVisibility, productImageData, state.images[key]?.url, state.imageStyle
      );
      setState((p:any) => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) {
      setState((p:any) => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } }));
    }
  };

  const handleBulkAction = async (type: 'image' | 'prompt') => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) {
      if (type === 'image') await handleGenImageForKey(key);
      else await handleGeneratePromptForKey(key);
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Thư viện ZIP chưa sẵn sàng.");
    const zip = new JSZip();
    let count = 0;
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    activeKeys.forEach((key, i) => {
      if (state.images[key]?.url) {
        const base64Data = state.images[key].url.split(',')[1];
        if (base64Data) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64Data, { base64: true }); count++; }
      }
    });
    if (count === 0) return alert("Không có ảnh để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `nonface_images_2_${state.productName || 'project'}.zip`;
    link.click();
  };

  const downloadAllPrompts = () => {
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const text = activeKeys.map(key => state.videoPrompts[key]?.text || "").filter(t => t.trim().length > 0).map(t => t.replace(/\n/g, ' ')).join('\n');
    if (!text) return alert("Vui lòng tạo Video Prompt trước khi tải xuống.");
    const blob = new Blob([text], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `prompts_nonface_2_${state.productName || 'project'}.txt`;
    link.click();
  };

  const hasGeneratedMedia = state.script && (Object.values(state.images).some((img: any) => img.url) || Object.values(state.videoPrompts).some((pr: any) => pr.text));

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8 mb-8">
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 border-b pb-6 gap-4">
           <div>
              <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Review Non-face 2</h2>
              <span className="bg-indigo-100 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mt-1 inline-block">Bộ Sưu Tập Video</span>
           </div>

           <div className="flex gap-2">
              <button 
                onClick={() => localJsonRef.current?.click()}
                className="px-6 py-3 bg-slate-100 text-slate-600 text-[10px] font-black rounded-xl hover:bg-slate-200 transition-all uppercase tracking-widest border border-slate-200"
              >
                Tải Data (Import)
              </button>
              <input type="file" ref={localJsonRef} onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => processImportData(JSON.parse(ev.target?.result as string)); r.readAsText(f); } e.target.value = ""; }} className="hidden" accept="application/json" />

              <button 
                onClick={handleLocalExportJson}
                className="px-6 py-3 bg-indigo-600 text-white text-[10px] font-black rounded-xl hover:bg-indigo-700 transition-all uppercase tracking-widest shadow-md"
              >
                Xuất file JSON
              </button>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-12 gap-10">
          <div className="md:col-span-5 space-y-6">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest px-1">1. Ảnh sản phẩm</label>
                <div onClick={() => productInputRef.current?.click()} className="w-full aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 overflow-hidden relative group hover:border-orange-400 transition-all">
                  {state.productPreviewUrls.length === 0 ? (
                    <div className="text-center opacity-40 group-hover:opacity-60">
                      <svg className="w-10 h-10 mx-auto text-orange-500 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                      <span className="text-[9px] font-black uppercase tracking-tighter">Tải ảnh SP</span>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 gap-1 w-full h-full relative">
                        <img src={state.productPreviewUrls[0]} className="w-full h-full object-cover" />
                        <div className="absolute bottom-2 right-2 bg-black/60 text-white text-[8px] font-bold px-2 py-1 rounded">+{state.productPreviewUrls.length}</div>
                    </div>
                  )}
                  <input type="file" multiple ref={productInputRef} onChange={handleProductFilesChange} className="hidden" accept="image/*" />
                </div>
              </div>

              <div className="space-y-2">
                <label className={`block text-[11px] font-black text-slate-500 uppercase tracking-widest px-1`}>2. Bàn tay mẫu</label>
                <div onClick={() => state.handVisibility === 'with_hand' && handInputRef.current?.click()} className={`w-full aspect-[3/4] border-2 border-dashed rounded-2xl flex items-center justify-center cursor-pointer bg-slate-50 overflow-hidden relative group transition-all`}>
                  {state.handPreviewUrl ? <img src={state.handPreviewUrl} className="h-full w-full object-cover" /> : <span className="text-[9px] font-black uppercase text-slate-400">Mẫu tay AI</span>}
                  <input type="file" ref={handInputRef} onChange={(e) => { if (e.target.files?.[0]) { const f = e.target.files[0]; setState((p:any) => ({ ...p, handFile: f, handPreviewUrl: URL.createObjectURL(f) })); } }} className="hidden" accept="image/*" />
                </div>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase px-1">Background & Visual Note</label>
              <div className="grid grid-cols-2 gap-4">
                <div onClick={() => backgroundInputRef.current?.click()} className="aspect-square border-2 border-dashed border-slate-200 rounded-[2rem] flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden group relative">
                  {state.backgroundPreviewUrl ? <img src={state.backgroundPreviewUrl} className="h-full w-full object-cover" /> : <span className="text-[10px] font-black text-slate-400 uppercase">Tải bối cảnh</span>}
                  <input type="file" ref={backgroundInputRef} onChange={(e) => { if (e.target.files?.[0]) { const f = e.target.files[0]; setState((p:any) => ({ ...p, backgroundFile: f, backgroundPreviewUrl: URL.createObjectURL(f) })); } }} className="hidden" accept="image/*" />
                </div>
                <textarea value={state.scriptNote} onChange={e => setState((p:any) => ({ ...p, scriptNote: e.target.value }))} placeholder="Mô tả bối cảnh..." className="w-full p-4 border border-slate-200 rounded-[2rem] text-xs h-full resize-none font-bold bg-slate-50 focus:bg-white outline-none" />
              </div>
            </div>
          </div>

          <div className="md:col-span-7 space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <input type="text" value={state.productName} onChange={e => setState((p:any) => ({ ...p, productName: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold outline-none" placeholder="Tên sản phẩm..." />
              <input type="text" value={state.targetAudience} onChange={e => setState((p:any) => ({ ...p, targetAudience: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none" placeholder="Tệp khách hàng..." />
            </div>
            <textarea value={state.keyword} onChange={e => setState((p:any) => ({ ...p, keyword: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl h-20 text-sm font-bold outline-none" placeholder="USP nổi bật..." />

            <div className="grid grid-cols-2 gap-4">
              <select value={state.gender} onChange={e => setState((p:any) => ({ ...p, gender: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none"><option value="Nữ">Nữ</option><option value="Nam">Nam</option></select>
              <select value={state.voice} onChange={e => setState((p:any) => ({ ...p, voice: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none">{VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}</select>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="flex bg-slate-50 p-1.5 rounded-2xl border"><button onClick={() => setState((p: any) => ({ ...p, imageStyle: 'Realistic' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white' : 'text-slate-400'}`}>Real</button><button onClick={() => setState((p: any) => ({ ...p, imageStyle: '3D' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white' : 'text-slate-400'}`}>3D</button></div>
               <select value={state.handVisibility} onChange={e => setState((p:any) => ({ ...p, handVisibility: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none"><option value="with_hand">Có tay người</option><option value="no_hand">Không tay</option></select>
            </div>

            <select value={state.scriptLayout} onChange={e => setState((p:any) => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none"><option value="">-- Random Layout --</option>{LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}</select>

            <div className="grid grid-cols-2 gap-4">
              <input list="nf2-addr" value={state.addressing} onChange={e => setState((p:any) => ({ ...p, addressing: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none" placeholder="Xưng hô..." />
              <datalist id="nf2-addr">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
              <select value={state.sceneCount} onChange={e => setState((p:any) => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-orange-600 outline-none">{SCENE_COUNT_OPTIONS.map(o => <option key={o.count} value={o.count}>{o.label}</option>)}</select>
            </div>
            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-5 bg-slate-900 text-white font-black rounded-3xl uppercase shadow-xl hover:bg-black transition-all tracking-widest active:scale-95 disabled:opacity-50">
              {state.isGeneratingScript ? "ĐANG XỬ LÝ..." : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-10 pb-32 animate-fadeIn">
          <div className="bg-slate-900 p-8 rounded-[3rem] border border-slate-800 shadow-2xl flex flex-col md:flex-row justify-between items-center gap-6">
            <div>
              <h3 className="text-xl font-black text-white uppercase tracking-tight">Kịch bản chi tiết ({state.sceneCount} cảnh)</h3>
            </div>
            <div className="flex flex-wrap justify-center gap-3">
              <button onClick={() => handleBulkAction('image')} className="px-6 py-4 bg-orange-600 text-white text-[11px] font-black rounded-2xl shadow-lg hover:bg-orange-700 transition-all uppercase">Vẽ tất cả ảnh</button>
              <button onClick={() => handleBulkAction('prompt')} className="px-6 py-4 bg-blue-600 text-white text-[11px] font-black rounded-2xl shadow-lg hover:bg-blue-700 transition-all uppercase">Tạo tất cả prompt</button>
              <button onClick={downloadAllImages} className="px-6 py-4 bg-white text-slate-900 text-[11px] font-black rounded-2xl shadow-lg hover:bg-slate-100 transition-all uppercase">Tải ZIP Ảnh</button>
              <button onClick={downloadAllPrompts} className="px-6 py-4 bg-indigo-600 text-white text-[11px] font-black rounded-2xl shadow-lg hover:bg-indigo-700 transition-all uppercase">Tải Prompt</button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-8">
            {Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`).map((key, idx) => (
              <div key={key} className="space-y-4">
                <ScriptSection title={`Phần ${idx + 1}`} content={state.script[key]} color="border-orange-500" onChange={(v) => setState((p:any) => ({ ...p, script: { ...p.script, [key]: v } }))} onRegenerate={() => handleRegenerateScriptPart(key)} isRegenerating={state.isRegeneratingPart[key]} />
                <ImageCard
                  label={`Cảnh ${idx + 1}`} imageData={state.images[key] || { url: '', loading: false }} videoPrompt={state.videoPrompts[key] || { text: '', loading: false, visible: false }}
                  onGeneratePrompt={() => handleGeneratePromptForKey(key)} onRegenerate={() => handleGenImageForKey(key)} onTranslate={() => {}}
                  poseOptions={NONFACE_POSES} pose={state.images[key]?.pose || ''} onPoseChange={(val) => setState((p:any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: val } } }))}
                  customPrompt={state.images[key]?.customPrompt || ''} onCustomPromptChange={(v) => setState((p:any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: v } } }))}
                />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default NonFaceReviewModule2;

import React, { useState, useEffect, useRef } from 'react';
import { ScriptParts } from '../types';
import * as service from '../services/nonFaceReview2Service';
import ScriptSection from '../components/ScriptSection';
import ImageCard from '../components/ImageCard';

declare var JSZip: any;

const LAYOUT_OPTIONS = [
  "Cận cảnh giày + nỗi đau khi đi giày cũ + trải nghiệm êm ái + giới thiệu chất liệu đế + các dịp sử dụng + CTA",
  "Mở hộp giày mới + đánh giá form dáng + đi thử lên chân + phối đồ thực tế + CTA",
  "Review độ bền + test nước/chống trượt + cảm nhận sau 1 ngày sử dụng + giới thiệu ưu đãi + CTA",
  "Nỗi đau đau chân/bí bách + giải pháp từ công nghệ lót giày + so sánh với giày thường + CTA",
  "Câu chuyện phối đồ + giày là điểm nhấn + cận cảnh đường chỉ/da + hướng dẫn chọn size + CTA"
];

const FOOTWEAR_POSES = [
  { "value": "", "label": "-- Tư thế giày dép --" },
  { "value": "walking_shot", "label": "Đang bước đi (Walking)" },
  { "value": "standing_on_floor", "label": "Đứng thẳng trên mặt sàn" },
  { "value": "side_view_resting", "label": "Gác chân/Nghiêng chân khoe dáng" },
  { "value": "putting_on_shoe", "label": "Đang xỏ chân vào giày" },
  { "value": "holding_by_hand", "label": "Cầm giày trên tay review" },
  { "value": "close_up_sole", "label": "Cận cảnh đế giày/lót giày" },
  { "value": "jumping_action", "label": "Nhảy nhẹ (Test độ đàn hồi)" },
  { "value": "top_down_view", "label": "Nhìn từ trên xuống (POV feet)" }
];

const SCENE_COUNT_OPTIONS = Array.from({ length: 13 }, (_, i) => {
  const count = i + 3;
  const seconds = count * 8;
  return { count, label: `${count} cảnh - ${seconds}s` };
});

const VOICE_OPTIONS = [
  "Giọng Bắc 20-40 tuổi",
  "Giọng Nam 20-40 tuổi",
  "Giọng Bắc 50-60 tuổi",
  "Giọng Nam 50-60 tuổi",
  "Giọng Bắc 60-80 tuổi",
  "Giọng Nam 60-80 tuổi"
];

const ADDRESSING_OPTIONS = [
  "em - anh chị",
  "tui - mấy bà",
  "mình - cả nhà",
  "tớ - các cậu",
  "mình - các bạn"
];

const NonFaceReviewModule2: React.FC = () => {
  const storageKey = "nonface_footwear_project_v1";
  const [state, setState] = useState<any>({
    backgroundFile: null,
    backgroundPreviewUrl: null,
    footFile: null, // Đổi từ hand sang foot
    footPreviewUrl: null,
    gender: 'Nữ',
    voice: 'Giọng Bắc 20-40 tuổi',
    addressing: '',
    targetAudience: '',
    imageStyle: 'Realistic',
    displayMode: 'on_foot', // 'no_foot' | 'beside_foot' | 'on_foot'
    sceneCount: 5,
    productFiles: [], 
    productPreviewUrls: [],
    productName: '',
    keyword: '',
    scriptNote: '', 
    visualNote: '',
    scriptLayout: '',
    isGeneratingScript: false,
    isRegeneratingPart: {},
    script: null,
    images: {},
    videoPrompts: {}
  });

  const productInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);
  const footInputRef = useRef<HTMLInputElement>(null);
  const localJsonRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            productFiles: [],
            backgroundFile: null,
            footFile: null,
            isGeneratingScript: false,
            isRegeneratingPart: {}
          }));
        }
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isRegeneratingPart, productFiles, backgroundFile, footFile, images, ...persistentData } = state;
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: images[key]?.url?.startsWith('data:') ? images[key].url : '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) {}
  }, [state]);

  const processImportData = async (importedData: any) => {
    if (!Array.isArray(importedData) || importedData.length === 0) return;
    window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 10, complete: false } }));

    try {
      const firstItem = importedData[0];
      const inputs = firstItem.inputs || {};
      const settings = inputs.settings || {};
      const media = inputs.inputMedia || {};

      const newState = {
        ...state,
        productName: inputs.productName || state.productName,
        keyword: inputs.keyword || state.keyword,
        targetAudience: inputs.targetAudience || state.targetAudience,
        visualNote: inputs.visualNote || state.visualNote,
        scriptNote: inputs.scriptNote || state.scriptNote,
        gender: settings.gender || state.gender,
        voice: settings.voice || state.voice,
        addressing: settings.addressing || state.addressing,
        imageStyle: settings.imageStyle || state.imageStyle,
        displayMode: settings.displayMode || 'on_foot',
        scriptLayout: settings.scriptLayout || state.scriptLayout,
        productPreviewUrls: media.productImages || [],
        backgroundPreviewUrl: media.backgroundImage || "",
        footPreviewUrl: media.footImage || "",
        sceneCount: importedData.length,
        script: {}, images: {}, videoPrompts: {}
      };

      for (let i = 0; i < importedData.length; i++) {
        const item = importedData[i];
        const key = `v${i + 1}`;
        const itemSettings = item.inputs?.settings || {};

        newState.script[key] = item.script || '';
        newState.images[key] = { 
          url: item.outputImage || '', 
          loading: false, 
          angle: itemSettings.angle || '', 
          pose: itemSettings.pose || '',
          customPrompt: '' 
        };
        newState.videoPrompts[key] = { 
          text: item.videoPrompt || '', 
          loading: false, 
          visible: !!item.videoPrompt 
        };

        const percent = Math.round(((i + 1) / importedData.length) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === importedData.length - 1 } }));
        await new Promise(r => setTimeout(r, 30));
      }
      setState(newState);
    } catch (e) {
      alert("Lỗi khi nạp dữ liệu JSON!");
    }
  };

  const handleExport = async () => {
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const exportData = activeKeys.map((key, index) => ({
      stt: index + 1,
      inputs: {
        productName: state.productName,
        keyword: state.keyword,
        targetAudience: state.targetAudience, 
        visualNote: state.visualNote,
        scriptNote: state.scriptNote, 
        inputMedia: {
          productImages: state.productPreviewUrls,
          backgroundImage: state.backgroundPreviewUrl,
          footImage: state.footPreviewUrl
        },
        settings: {
          gender: state.gender,
          voice: state.voice,
          addressing: state.addressing,
          imageStyle: state.imageStyle,
          displayMode: state.displayMode,
          scriptLayout: state.scriptLayout,
          angle: state.images[key]?.angle || '',
          pose: state.images[key]?.pose || ''
        }
      },
      script: state.script ? state.script[key] : '',
      outputImage: state.images[key]?.url || '',
      videoPrompt: state.videoPrompts[key]?.text || ''
    }));
    return exportData;
  };

  useEffect(() => {
    const onGlobalExport = async () => {
      const data = await handleExport();
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { detail: { data, moduleName: 'Giay_Dep_Review' } }));
    };
    const onGlobalImport = (e: any) => processImportData(e.detail);
    window.addEventListener('REQUEST_EXPORT_DATA', onGlobalExport);
    window.addEventListener('REQUEST_IMPORT_DATA', onGlobalImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', onGlobalExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', onGlobalImport);
    };
  }, [state]);

  const handleLocalExportJson = async () => {
    const data = await handleExport();
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `GiayDep_${state.productName || 'Project'}_${Date.now()}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleProductFilesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const selectedFiles = Array.from(e.target.files);
      const updatedFiles = [...state.productFiles, ...selectedFiles].slice(0, 3);
      const updatedUrls = updatedFiles.map(f => URL.createObjectURL(f));
      setState((prev: any) => ({ ...prev, productFiles: updatedFiles, productPreviewUrls: updatedUrls }));
    }
  };

  const handleGenerate = async () => {
    if (state.productFiles.length === 0 && state.productPreviewUrls.length === 0) return alert("Vui lòng tải ảnh giày dép.");
    if (!state.productName) return alert("Vui lòng nhập tên sản phẩm.");

    setState((prev: any) => ({ ...prev, isGeneratingScript: true }));
    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }

      let layoutToUse = state.scriptLayout;
      if (!layoutToUse) layoutToUse = LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateNonFaceScript(
        imageParts, state.productName, state.keyword, layoutToUse, 
        state.gender, state.voice, state.addressing, state.sceneCount, state.targetAudience
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse, isGeneratingScript: false }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, isGeneratingScript: false }));
    }
  };

  const handleRegenerateScriptPart = async (key: string) => {
    if (state.isGeneratingScript || state.isRegeneratingPart[key] || !state.script) return;
    setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: true } }));
    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }
      const newPartContent = await service.regenerateNonFaceScriptPart(
        imageParts, state.productName, state.keyword, key, state.script[key], state.script, state.gender, state.voice, state.addressing, state.targetAudience
      );
      setState((p: any) => ({ ...p, script: { ...p.script, [key]: newPartContent }, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } }));
    } catch (error) {
      setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } }));
    }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      let productParts = state.productFiles.length > 0 
        ? await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)))
        : state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));

      const bgRefPart = state.backgroundFile ? await service.fileToGenerativePart(state.backgroundFile) : 
                       (state.backgroundPreviewUrl?.startsWith('data:') ? { mimeType: 'image/png', data: state.backgroundPreviewUrl.split(',')[1] } : null);

      const footRefPart = state.footFile ? await service.fileToGenerativePart(state.footFile) : 
                       (state.footPreviewUrl?.startsWith('data:') ? { mimeType: 'image/png', data: state.footPreviewUrl.split(',')[1] } : null);

      const poseLabel = FOOTWEAR_POSES.find(p => p.value === state.images[key]?.pose)?.label || "";

      const url = await service.generateFootwearImage(
        productParts, footRefPart, state.productName, state.script[key], state.images[key]?.customPrompt,
        state.imageStyle, state.displayMode, state.scriptNote, state.visualNote, bgRefPart, state.images[key]?.angle, poseLabel
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, videoPrompts: { ...prev.videoPrompts, [key]: { ...prev.videoPrompts[key], loading: true, visible: true } } }));
    try {
      let productImageData = state.productFiles[0] ? (await service.fileToGenerativePart(state.productFiles[0])).data : (state.productPreviewUrls[0]?.split(',')[1] || "");
      const prompt = await service.generateFootwearVeoPrompt(
        state.productName, state.script[key], state.gender, state.voice, state.displayMode, productImageData, state.images[key]?.url, state.imageStyle
      );
      setState((p:any) => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) {
      setState((p:any) => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } }));
    }
  };

  const handleBulkAction = async (type: 'image' | 'prompt') => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) {
      if (type === 'image') await handleGenImageForKey(key);
      else await handleGeneratePromptForKey(key);
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Thư viện ZIP chưa sẵn sàng.");
    const zip = new JSZip();
    let count = 0;
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    activeKeys.forEach((key, i) => {
      if (state.images[key]?.url) {
        const base64Data = state.images[key].url.split(',')[1];
        if (base64Data) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64Data, { base64: true }); count++; }
      }
    });
    if (count === 0) return alert("Không có ảnh để tải.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `giay_dep_images_${state.productName || 'project'}.zip`;
    link.click();
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8 mb-8">
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 border-b pb-6 gap-4">
           <div>
              <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Review Giày Dép AI</h2>
              <span className="bg-indigo-100 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mt-1 inline-block">Chuyên biệt Footwear</span>
           </div>

           <div className="flex gap-2">
              <button onClick={() => localJsonRef.current?.click()} className="px-6 py-3 bg-slate-100 text-slate-600 text-[10px] font-black rounded-xl hover:bg-slate-200 transition-all uppercase tracking-widest border border-slate-200">Tải Data (Import)</button>
              <input type="file" ref={localJsonRef} onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => processImportData(JSON.parse(ev.target?.result as string)); r.readAsText(f); } e.target.value = ""; }} className="hidden" accept="application/json" />
