  } catch (error) { return currentPartContent; }
};

export const generateFootwearImage = async (
  referenceImageParts: any[], 
  footReferencePart: any | null,
  productName: string,
  scriptPart: string, 
  userCustomPrompt: string | undefined, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  displayMode: 'no_foot' | 'beside_foot' | 'on_foot' = 'on_foot',
  backgroundNote: string = "",
  visualNote: string = "",
  backgroundReferencePart: any | null = null,
  productAngle: string = "",
  poseLabel: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const baseStyle = is3D ? "3D Animation Pixar style, high-quality CGI" : "Photorealistic high-end commercial footwear photography, 8k, cinematic lighting";

  let interactionRule = "";
  if (displayMode === 'on_foot') {
    interactionRule = `!!! MANDATORY: The character is WEARING the footwear on their feet. Show the interaction between the feet and the shoes. ${footReferencePart ? "Reference the foot shape from FOOT_REF." : ""}`;
  } else if (displayMode === 'beside_foot') {
    interactionRule = "Show the shoes placed neatly on the floor NEXT TO the character's feet. The character is barefoot or wearing socks.";
  } else {
    interactionRule = "!!! STRICT RULE: ABSOLUTELY NO PEOPLE, NO FEET, NO LEGS. Product-only hero shot on a clean surface.";
  }

  const visualRules = `
    1. PRODUCT FIDELITY: The footwear "${productName}" MUST be 100% identical to the reference product images. Preserve sole textures and patterns.
    2. NO TEXT: Strictly no text, labels, logos, or UI elements.
    3. ANGLE: ${productAngle || "professional view"}. POSE: ${poseLabel || "natural"}.
  `;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16.
    ${interactionRule}
    ${visualRules}
    ENVIRONMENT: ${backgroundReferencePart ? "Use background from BACKGROUND_REF." : (backgroundNote || "Stylish indoor/outdoor setting")}.
    ${visualNote ? `LAYOUT NOTE: ${visualNote}.` : ""}
    SCENE CONTENT: "${scriptPart}". 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (footReferencePart) contents.push({ inlineData: footReferencePart });
  referenceImageParts.forEach(part => contents.push({ inlineData: part }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part) throw new Error("Fail");
    return `data:image/png;base64,${part.inlineData.data}`;
  } catch (error) { throw error; }
};

export const generateFootwearVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  displayMode: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const interaction = displayMode === 'on_foot' 
    ? "Character is walking or moving their feet naturally while wearing the shoes."
    : "Camera movements around the product.";

  const instructionPrompt = `
  Write a VEO-3 video prompt (8s). 
  FOCUS: Footwear "${productName}". Style: ${is3D ? "3D Animation" : "Photorealistic"}.
  ACTION: ${interaction}. Scene: "${scriptText}".
  VOICE: Model performs Voice-over with characteristics: ${voiceDetail}.
  9:16 ratio, 4K, 60fps. Single continuous shot. No text.
  Return 1 single line in English.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({ model: "gemini-3-flash-preview", contents });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) { return ""; }
};

