  scriptPart: string, 
  userCustomPrompt: string | undefined, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  displayMode: 'no_foot' | 'beside_foot' | 'on_foot' = 'on_foot',
  backgroundNote: string = "",
  visualNote: string = "",
  backgroundReferencePart: any | null = null,
  productAngle: string = "",
  poseLabel: string = ""
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  // Style cơ bản
  const baseStyle = is3D 
    ? "High-quality 3D Animation, Pixar character style, polished CGI, vibrant colors." 
    : "Ultra-realistic raw commercial photography, 8k resolution, cinematic lighting, sharp focus on footwear textures.";

  // QUY TẮC VẬT LÝ TUYỆT ĐỐI ĐỂ TRÁNH CHÂN BAY
  const physicsRules = `
    !!! CRITICAL PHYSICAL REALISM (MANDATORY) !!!:
    1. FLOOR CONTACT: The feet and shoes MUST be firmly planted on the ground surface. Use realistic "contact shadows" where the sole meets the floor.
    2. GRAVITY: Show natural weight distribution. If the person is standing, the heels and soles must look pressed against the floor.
    3. NO FLOATING: Absolutely no floating shoes or hovering feet. Everything must be grounded.
    4. ANATOMY: The connection between the legs, ankles, and feet must be anatomically correct and look like a real person.
    5. SKIN TEXTURE: Natural human skin texture for legs, with subtle micro-folds at the joints (ankles/knees) to prove realism.
  `;

  let interactionRule = "";
  if (displayMode === 'on_foot') {
    interactionRule = `MANDATORY: A Vietnamese person is WEARING the ${productName} on their feet. Show the natural interaction between the skin and the shoe straps/material. ${footReferencePart ? "Follow the foot shape from the FOOT_REFERENCE image." : ""}`;
  } else if (displayMode === 'beside_foot') {
    interactionRule = `Show the ${productName} placed neatly on the floor directly NEXT TO the person's bare feet. The person is standing on the floor.`;
  } else {
    interactionRule = "!!! STRICT RULE: PRODUCT ONLY. NO PEOPLE, NO FEET, NO LEGS. Show the shoes on a realistic floor or pedestal.";
  }

  const visualRules = `
    - PRODUCT FIDELITY: The ${productName} MUST be 100% identical to the reference product images. Preserve patterns and materials.
    - NO TEXT: Strictly no text, labels, or watermarks.
    - COMPOSITION: ${productAngle || "Eye-level or low-angle professional footwear shot"}.
    - POSE: ${poseLabel || "Natural stance"}.
  `;

  const prompt = `
    ${baseStyle} Aspect ratio 9:16.
    ${physicsRules}
    ${interactionRule}
    ${visualRules}
    ENVIRONMENT: ${backgroundReferencePart ? "Use background from BACKGROUND_REFERENCE." : (backgroundNote || "High-end fashion retail store or modern home interior")}.
    SCENE CONTEXT: "${scriptPart}". 
    ${visualNote ? `LAYOUT: ${visualNote}.` : ""}
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (footReferencePart) contents.push({ inlineData: footReferencePart });
  referenceImageParts.forEach(part => contents.push({ inlineData: part }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const part = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!part) throw new Error("Fail");
    return `data:image/png;base64,${part.inlineData.data}`;
  } catch (error) { throw error; }
};

export const generateFootwearVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  displayMode: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const action = displayMode === 'on_foot' 
    ? "Character walks or shifts weight naturally while wearing the shoes on a solid floor."
    : "Slow camera orbit around the shoes placed on the ground.";

  const instructionPrompt = `
  Write a detailed VEO-3 video prompt (8s). 
  FOCUS: Footwear "${productName}". Style: ${is3D ? "3D Animation" : "Photorealistic"}.
  PHYSICS: Feet must stay grounded on the floor at all times. Realistic contact and shadows.
  ACTION: ${action}. Dialogue: "${scriptText}".
  VOICE: ${voiceDetail}. 
  9:16 ratio, 4K, 60fps. Continuous shot. No cuts. No text.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({ model: "gemini-3-flash-preview", contents });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) { return ""; }
};

