              <input type="file" ref={localJsonRef} onChange={e => { const f = e.target.files?.[0]; if (f) { const r = new FileReader(); r.onload = (ev) => processImportData(JSON.parse(ev.target?.result as string)); r.readAsText(f); } e.target.value = ""; }} className="hidden" accept="application/json" />
              <button onClick={handleLocalExportJson} className="px-6 py-3 bg-indigo-600 text-white text-[10px] font-black rounded-xl hover:bg-indigo-700 transition-all uppercase tracking-widest shadow-md">Xuất file JSON</button>
           </div>
