                <label className={`block text-[11px] font-black text-slate-500 uppercase tracking-widest px-1`}>2. Bàn chân mẫu (Ref)</label>
                <div onClick={() => footInputRef.current?.click()} className={`w-full aspect-[3/4] border-2 border-dashed rounded-2xl flex items-center justify-center cursor-pointer bg-slate-50 overflow-hidden relative group transition-all`}>
                  {state.footPreviewUrl ? <img src={state.footPreviewUrl} className="h-full w-full object-cover" /> : (
                    <div className="text-center opacity-40">
                      <svg className="w-10 h-10 mx-auto text-slate-400 mb-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
