                </div>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase px-1">Bối cảnh & Visual Note</label>
              <div className="grid grid-cols-2 gap-4">
                <div onClick={() => backgroundInputRef.current?.click()} className="aspect-square border-2 border-dashed border-slate-200 rounded-[2rem] flex items-center justify-center bg-slate-50 cursor-pointer overflow-hidden group relative">
                  {state.backgroundPreviewUrl ? <img src={state.backgroundPreviewUrl} className="h-full w-full object-cover" /> : <span className="text-[10px] font-black text-slate-400 uppercase">Tải bối cảnh</span>}
                  <input type="file" ref={backgroundInputRef} onChange={(e) => { if (e.target.files?.[0]) { const f = e.target.files[0]; setState((p:any) => ({ ...p, backgroundFile: f, backgroundPreviewUrl: URL.createObjectURL(f) })); } }} className="hidden" accept="image/*" />
                </div>
                <textarea value={state.scriptNote} onChange={e => setState((p:any) => ({ ...p, scriptNote: e.target.value }))} placeholder="Mô tả bối cảnh..." className="w-full p-4 border border-slate-200 rounded-[2rem] text-xs h-full resize-none font-bold bg-slate-50 focus:bg-white outline-none" />
              </div>
            </div>
          </div>

          <div className="md:col-span-7 space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <input type="text" value={state.productName} onChange={e => setState((p:any) => ({ ...p, productName: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold outline-none" placeholder="Tên giày/dép..." />
              <input type="text" value={state.targetAudience} onChange={e => setState((p:any) => ({ ...p, targetAudience: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold outline-none" placeholder="Tệp khách hàng..." />
            </div>
            <textarea value={state.keyword} onChange={e => setState((p:any) => ({ ...p, keyword: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl h-20 text-sm font-bold outline-none" placeholder="USP nổi bật (Đế êm, chống trượt, da thật...)" />

            <div className="grid grid-cols-2 gap-4">
              <select value={state.gender} onChange={e => setState((p:any) => ({ ...p, gender: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none"><option value="Nữ">Người mẫu Nữ</option><option value="Nam">Người mẫu Nam</option></select>
              <select value={state.voice} onChange={e => setState((p:any) => ({ ...p, voice: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none">{VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}</select>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="flex bg-slate-50 p-1.5 rounded-2xl border"><button onClick={() => setState((p: any) => ({ ...p, imageStyle: 'Realistic' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white' : 'text-slate-400'}`}>Real</button><button onClick={() => setState((p: any) => ({ ...p, imageStyle: '3D' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white' : 'text-slate-400'}`}>3D</button></div>
               <select value={state.displayMode} onChange={e => setState((p:any) => ({ ...p, displayMode: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-indigo-600 outline-none">
                  <option value="on_foot">Đang đi vào chân (Wearing)</option>
                  <option value="beside_foot">Đặt cạnh chân (Beside)</option>
                  <option value="no_foot">Chỉ sản phẩm (Product only)</option>
               </select>
            </div>

            <select value={state.scriptLayout} onChange={e => setState((p:any) => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none"><option value="">-- Random Layout --</option>{LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}</select>

            <div className="grid grid-cols-2 gap-4">
              <input list="nf2-addr" value={state.addressing} onChange={e => setState((p:any) => ({ ...p, addressing: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none" placeholder="Xưng hô..." />
              <datalist id="nf2-addr">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
              <select value={state.sceneCount} onChange={e => setState((p:any) => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-orange-600 outline-none">{SCENE_COUNT_OPTIONS.map(o => <option key={o.count} value={o.count}>{o.label}</option>)}</select>
            </div>
            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-5 bg-slate-900 text-white font-black rounded-3xl uppercase shadow-xl hover:bg-black transition-all tracking-widest active:scale-95 disabled:opacity-50">
              {state.isGeneratingScript ? "ĐANG TẠO KỊCH BẢN GIÀY..." : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-10 pb-32 animate-fadeIn">
          <div className="bg-slate-900 p-8 rounded-[3rem] border border-slate-800 shadow-2xl flex flex-col md:flex-row justify-between items-center gap-6">
            <div>
              <h3 className="text-xl font-black text-white uppercase tracking-tight">Timeline ({state.sceneCount} cảnh)</h3>
              <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest mt-1">Góc máy sát sàn • Trọng lực thực tế</p>
            </div>
            <div className="flex flex-wrap justify-center gap-3">
              <button onClick={() => handleBulkAction('image')} className="px-6 py-4 bg-orange-600 text-white text-[11px] font-black rounded-2xl shadow-lg hover:bg-orange-700 transition-all uppercase">Vẽ tất cả ảnh</button>
              <button onClick={() => handleBulkAction('prompt')} className="px-6 py-4 bg-blue-600 text-white text-[11px] font-black rounded-2xl shadow-lg hover:bg-blue-700 transition-all uppercase">Tạo tất cả prompt</button>
              <button onClick={downloadAllImages} className="px-6 py-4 bg-white text-slate-900 text-[11px] font-black rounded-2xl shadow-lg hover:bg-slate-100 transition-all uppercase">ZIP Ảnh</button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-8">
            {Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`).map((key, idx) => (
              <div key={key} className="space-y-4">
                <ScriptSection title={`Phần ${idx + 1}`} content={state.script[key]} color="border-orange-500" onChange={(v) => setState((p:any) => ({ ...p, script: { ...p.script, [key]: v } }))} onRegenerate={() => handleRegenerateScriptPart(key)} isRegenerating={state.isRegeneratingPart[key]} />
                <ImageCard
                  label={`Cảnh ${idx + 1}`} imageData={state.images[key] || { url: '', loading: false }} videoPrompt={state.videoPrompts[key] || { text: '', loading: false, visible: false }}
                  onGeneratePrompt={() => handleGeneratePromptForKey(key)} onRegenerate={() => handleGenImageForKey(key)} onTranslate={() => {}}
                  poseOptions={FOOTWEAR_POSES} pose={state.images[key]?.pose || ''} onPoseChange={(val) => setState((p:any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: val } } }))}
                  customPrompt={state.images[key]?.customPrompt || ''} onCustomPromptChange={(v) => setState((p:any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: v } } }))}
                />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default NonFaceReviewModule2;

import React, { useState, useEffect, useRef } from 'react';
import { ScriptParts } from '../types';
import * as service from '../services/nonFaceReview2Service';
import ScriptSection from '../components/ScriptSection';
import ImageCard from '../components/ImageCard';

declare var JSZip: any;

const LAYOUT_OPTIONS = [
  "Cận cảnh giày + nỗi đau khi đi giày cũ + trải nghiệm thực tế + giới thiệu chất liệu đế + các dịp sử dụng + CTA",
  "Mở hộp giày mới + đánh giá form dáng + đi thử lên chân + phối đồ thực tế + CTA",
  "Review độ bền + test nước/chống trượt + cảm nhận sau 1 ngày sử dụng + giới thiệu ưu đãi + CTA",
  "Nỗi đau đau chân/bí bách + giải pháp từ công nghệ lót giày + so sánh với giày thường + CTA",
  "Câu chuyện phối đồ + giày là điểm nhấn + cận cảnh đường chỉ/da + hướng dẫn chọn size + CTA"
];

const FOOTWEAR_POSES = [
  { "value": "", "label": "-- Tư thế giày dép --" },
  { "value": "standing_firmly_floor", "label": "Đứng vững trên sàn (Góc ngang)" },
  { "value": "walking_cycle_side", "label": "Đang bước đi (Góc nghiêng)" },
  { "value": "low_angle_toe_up", "label": "Góc thấp - Nhấc mũi chân khoe đế" },
  { "value": "putting_on_shoe_sitting", "label": "Ngồi xỏ giày (Sitting & Wearing)" },
  { "value": "crossing_legs_showing_side", "label": "Gác chân khoe dáng bên (Side profile)" },
  { "value": "pov_looking_down_at_feet", "label": "Nhìn xuống chân (POV perspective)" },
  { "value": "close_up_heel_strike", "label": "Cận cảnh gót chân chạm đất" },
  { "value": "standing_on_tiptoes", "label": "Đứng nhón chân (Test độ dẻo)" }
];

const SCENE_COUNT_OPTIONS = Array.from({ length: 13 }, (_, i) => {
  const count = i + 3;
  const seconds = count * 8;
  return { count, label: `${count} cảnh - ${seconds}s` };
});

const VOICE_OPTIONS = [
  "Giọng Bắc 20-40 tuổi",
  "Giọng Nam 20-40 tuổi",
  "Giọng Bắc 50-60 tuổi",
  "Giọng Nam 50-60 tuổi",
  "Giọng Bắc 60-80 tuổi",
  "Giọng Nam 60-80 tuổi"
];

const ADDRESSING_OPTIONS = [
  "em - anh chị",
  "tui - mấy bà",
  "mình - cả nhà",
  "tớ - các cậu",
  "mình - các bạn"
];

const NonFaceReviewModule2: React.FC = () => {
  const storageKey = "nonface_footwear_project_v1_grounded";
  const [state, setState] = useState<any>({
    backgroundFile: null,
    backgroundPreviewUrl: null,
    footFile: null,
    footPreviewUrl: null,
    gender: 'Nữ',
    voice: 'Giọng Bắc 20-40 tuổi',
    addressing: '',
    targetAudience: '',
    imageStyle: 'Realistic',
    displayMode: 'on_foot', 
    sceneCount: 5,
    productFiles: [], 
    productPreviewUrls: [],
    productName: '',
    keyword: '',
    scriptNote: '', 
    visualNote: '',
    scriptLayout: '',
    isGeneratingScript: false,
    isRegeneratingPart: {},
    script: null,
    images: {},
    videoPrompts: {}
  });

  const productInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);
  const footInputRef = useRef<HTMLInputElement>(null);
  const localJsonRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            productFiles: [],
            backgroundFile: null,
            footFile: null,
            isGeneratingScript: false,
            isRegeneratingPart: {}
          }));
        }
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isRegeneratingPart, productFiles, backgroundFile, footFile, images, ...persistentData } = state;
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: images[key]?.url?.startsWith('data:') ? images[key].url : '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) {}
  }, [state]);

  const processImportData = async (importedData: any) => {
    if (!Array.isArray(importedData) || importedData.length === 0) return;
    window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 10, complete: false } }));

    try {
      const firstItem = importedData[0];
      const inputs = firstItem.inputs || {};
      const settings = inputs.settings || {};
      const media = inputs.inputMedia || {};

      const newState = {
        ...state,
        productName: inputs.productName || state.productName,
        keyword: inputs.keyword || state.keyword,
        targetAudience: inputs.targetAudience || state.targetAudience,
        visualNote: inputs.visualNote || state.visualNote,
        scriptNote: inputs.scriptNote || state.scriptNote,
        gender: settings.gender || state.gender,
        voice: settings.voice || state.voice,
        addressing: settings.addressing || state.addressing,
        imageStyle: settings.imageStyle || state.imageStyle,
        displayMode: settings.displayMode || 'on_foot',
        scriptLayout: settings.scriptLayout || state.scriptLayout,
        productPreviewUrls: media.productImages || [],
        backgroundPreviewUrl: media.backgroundImage || "",
        footPreviewUrl: media.footImage || "",
        sceneCount: importedData.length,
        script: {}, images: {}, videoPrompts: {}
      };

      for (let i = 0; i < importedData.length; i++) {
        const item = importedData[i];
        const key = `v${i + 1}`;
        const itemSettings = item.inputs?.settings || {};

        newState.script[key] = item.script || '';
        newState.images[key] = { 
          url: item.outputImage || '', 
          loading: false, 
          angle: itemSettings.angle || '', 
          pose: itemSettings.pose || '',
          customPrompt: '' 
        };
        newState.videoPrompts[key] = { 
          text: item.videoPrompt || '', 
          loading: false, 
          visible: !!item.videoPrompt 
        };

        const percent = Math.round(((i + 1) / importedData.length) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent, complete: i === importedData.length - 1 } }));
        await new Promise(r => setTimeout(r, 30));
      }
      setState(newState);
    } catch (e) {
      alert("Lỗi khi nạp dữ liệu JSON!");
    }
  };

  const handleExport = async () => {
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const exportData = activeKeys.map((key, index) => ({
      stt: index + 1,
      inputs: {
        productName: state.productName,
        keyword: state.keyword,
        targetAudience: state.targetAudience, 
        visualNote: state.visualNote,
        scriptNote: state.scriptNote, 
        inputMedia: {
          productImages: state.productPreviewUrls,
          backgroundImage: state.backgroundPreviewUrl,
          footImage: state.footPreviewUrl
        },
        settings: {
          gender: state.gender,
          voice: state.voice,
          addressing: state.addressing,
          imageStyle: state.imageStyle,
          displayMode: state.displayMode,
          scriptLayout: state.scriptLayout,
          angle: state.images[key]?.angle || '',
          pose: state.images[key]?.pose || ''
        }
      },
      script: state.script ? state.script[key] : '',
      outputImage: state.images[key]?.url || '',
      videoPrompt: state.videoPrompts[key]?.text || ''
    }));
    return exportData;
  };

  useEffect(() => {
    const onGlobalExport = async () => {
      const data = await handleExport();
      window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { detail: { data, moduleName: 'Giay_Dep_Review' } }));
    };
    const onGlobalImport = (e: any) => processImportData(e.detail);
    window.addEventListener('REQUEST_EXPORT_DATA', onGlobalExport);
    window.addEventListener('REQUEST_IMPORT_DATA', onGlobalImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', onGlobalExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', onGlobalImport);
    };
  }, [state]);

  const handleLocalExportJson = async () => {
    const data = await handleExport();
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `GiayDep_${state.productName || 'Project'}_${Date.now()}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleProductFilesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const selectedFiles = Array.from(e.target.files);
      const updatedFiles = [...state.productFiles, ...selectedFiles].slice(0, 5);
      const updatedUrls = updatedFiles.map(f => URL.createObjectURL(f));
      setState((prev: any) => ({ ...prev, productFiles: updatedFiles, productPreviewUrls: updatedUrls }));
    }
  };

  const removeProductFile = (idx: number) => {
    const updatedFiles = state.productFiles.filter((_: any, i: number) => i !== idx);
    const updatedPreviewUrls = state.productPreviewUrls.filter((_: any, i: number) => i !== idx);
    setState((prev: any) => ({ ...prev, productFiles: updatedFiles, productPreviewUrls: updatedPreviewUrls }));
  };

  const handleGenerate = async () => {
    if (state.productFiles.length === 0 && state.productPreviewUrls.length === 0) return alert("Vui lòng tải ảnh giày dép.");
    if (!state.productName) return alert("Vui lòng nhập tên sản phẩm.");

    setState((prev: any) => ({ ...prev, isGeneratingScript: true }));
    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }

      let layoutToUse = state.scriptLayout;
      if (!layoutToUse) layoutToUse = LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateNonFaceScript(
        imageParts, state.productName, state.keyword, layoutToUse, 
        state.gender, state.voice, state.addressing, state.sceneCount, state.targetAudience
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse, isGeneratingScript: false }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, isGeneratingScript: false }));
    }
  };

  const handleRegenerateScriptPart = async (key: string) => {
    if (state.isGeneratingScript || state.isRegeneratingPart[key] || !state.script) return;
    setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: true } }));
    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }
      const newPartContent = await service.regenerateNonFaceScriptPart(
        imageParts, state.productName, state.keyword, key, state.script[key], state.script, state.gender, state.voice, state.addressing, state.targetAudience
      );
      setState((p: any) => ({ ...p, script: { ...p.script, [key]: newPartContent }, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } }));
    } catch (error) {
      setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } }));
    }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      let productParts = state.productFiles.length > 0 
        ? await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)))
        : state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));

      const bgRefPart = state.backgroundFile ? await service.fileToGenerativePart(state.backgroundFile) : 
                       (state.backgroundPreviewUrl?.startsWith('data:') ? { mimeType: 'image/png', data: state.backgroundPreviewUrl.split(',')[1] } : null);

      const footRefPart = state.footFile ? await service.fileToGenerativePart(state.footFile) : 
                       (state.footPreviewUrl?.startsWith('data:') ? { mimeType: 'image/png', data: state.footPreviewUrl.split(',')[1] } : null);

      const poseLabel = FOOTWEAR_POSES.find(p => p.value === state.images[key]?.pose)?.label || "";

      const url = await service.generateFootwearImage(
        productParts, footRefPart, state.productName, state.script[key], state.images[key]?.customPrompt,
        state.imageStyle, state.displayMode, state.scriptNote, state.visualNote, bgRefPart, state.images[key]?.angle, poseLabel
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, videoPrompts: { ...prev.videoPrompts, [key]: { ...prev.videoPrompts[key], loading: true, visible: true } } }));
    try {
      let productImageData = state.productFiles[0] ? (await service.fileToGenerativePart(state.productFiles[0])).data : (state.productPreviewUrls[0]?.split(',')[1] || "");
      const prompt = await service.generateFootwearVeoPrompt(
        state.productName, state.script[key], state.gender, state.voice, state.displayMode, productImageData, state.images[key]?.url, state.imageStyle
      );
      setState((p:any) => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) {
      setState((p:any) => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } }));
    }
  };

  const handleBulkAction = async (type: 'image' | 'prompt') => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) {
      if (type === 'image') await handleGenImageForKey(key);
      else await handleGeneratePromptForKey(key);
    }
  };

