                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest px-1">1. Ảnh giày/dép (Max 3)</label>
                <div onClick={() => productInputRef.current?.click()} className="w-full h-32 border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all group overflow-hidden relative">
                    <div className="text-center opacity-40 group-hover:opacity-60">
                      <svg className="w-8 h-8 mx-auto text-orange-500 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
