                    </div>
                  <input type="file" multiple ref={productInputRef} onChange={handleProductFilesChange} className="hidden" accept="image/*" />
                </div>
                {state.productPreviewUrls.length > 0 && (
                  <div className="grid grid-cols-3 gap-2 mt-2">
