            <div className="grid grid-cols-2 gap-4">
               <div className="flex bg-slate-50 p-1.5 rounded-2xl border shadow-inner">
                  <button onClick={() => setState((p: any) => ({ ...p, imageStyle: 'Realistic' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400'}`}>Real</button>
