            <div className="grid grid-cols-2 gap-4">
              <input list="nf2-addr" value={state.addressing} onChange={e => setState((p:any) => ({ ...p, addressing: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none focus:ring-2 focus:ring-orange-100" placeholder="Xưng hô..." />
              <datalist id="nf2-addr">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
              <select value={state.sceneCount} onChange={e => setState((p:any) => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-orange-600 outline-none">
                {SCENE_COUNT_OPTIONS.map(o => <option key={o.count} value={o.count}>{o.label}</option>)}
              </select>
            </div>
            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-5 bg-slate-900 text-white font-black rounded-3xl uppercase shadow-xl hover:bg-black transition-all tracking-widest active:scale-95 disabled:opacity-50">
              {state.isGeneratingScript ? "ĐANG TẠO KỊCH BẢN GIÀY..." : "BẮT ĐẦU TẠO CHIẾN DỊCH"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-10 pb-32 animate-fadeIn">
          <div className="bg-slate-900 p-8 rounded-[3rem] border border-slate-800 shadow-2xl flex flex-col md:flex-row justify-between items-center gap-6">
            <div>
              <h3 className="text-xl font-black text-white uppercase tracking-tight">Timeline ({state.sceneCount} cảnh)</h3>
              <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest mt-1">Góc máy sát sàn • Trọng lực thực tế</p>
            </div>
            <div className="flex flex-wrap justify-center gap-3">
              <button onClick={() => handleBulkAction('image')} className="px-6 py-4 bg-orange-600 text-white text-[11px] font-black rounded-2xl shadow-lg hover:bg-orange-700 transition-all uppercase">Vẽ tất cả ảnh</button>
              <button onClick={() => handleBulkAction('prompt')} className="px-6 py-4 bg-blue-600 text-white text-[11px] font-black rounded-2xl shadow-lg hover:bg-blue-700 transition-all uppercase">Tạo tất cả prompt</button>
              <button onClick={downloadAllImages} className="px-6 py-4 bg-white text-slate-900 text-[11px] font-black rounded-2xl shadow-lg hover:bg-slate-100 transition-all uppercase">ZIP Ảnh</button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-8">
            {Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`).map((key, idx) => (
              <div key={key} className="space-y-4">
                <ScriptSection title={`Phần ${idx + 1}`} content={state.script[key]} color="border-orange-500" onChange={(v) => setState((p:any) => ({ ...p, script: { ...p.script, [key]: v } }))} onRegenerate={() => handleRegenerateScriptPart(key)} isRegenerating={state.isRegeneratingPart[key]} />
                <ImageCard
                  label={`Cảnh ${idx + 1}`} imageData={state.images[key] || { url: '', loading: false }} videoPrompt={state.videoPrompts[key] || { text: '', loading: false, visible: false }}
                  onGeneratePrompt={() => handleGeneratePromptForKey(key)} onRegenerate={() => handleGenImageForKey(key)} onTranslate={() => {}}
                  onDelete={() => setState((p:any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], url: '', loading: false } } }))}
                  poseOptions={FOOTWEAR_POSES} pose={state.images[key]?.pose || ''} onPoseChange={(val) => setState((p:any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: val } } }))}
                  customPrompt={state.images[key]?.customPrompt || ''} onCustomPromptChange={(v) => setState((p:any) => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: v } } }))}
                />
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default NonFaceReviewModule2;

import { GoogleGenAI, Type } from "@google/genai";
import { ScriptParts } from "../types";
import { getAiClient } from "./keyService";

const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const FORBIDDEN_TERMS = `Facebook, Shopee, Lazada, Tiki, Zalo, QR, Sale sốc, Mua ngay, Cam kết.`;

const getVoiceDetailedInstruction = (voiceLabel: string) => {
  const mapping: Record<string, string> = {
    "Giọng Bắc 20-40 tuổi": "Northern Vietnamese (Hanoi) accent, energetic, fast-paced, cheerful, youthful vibe",
    "Giọng Nam 20-40 tuổi": "Southern Vietnamese (Saigon) accent, energetic, fast-paced, cheerful, youthful vibe",
    "Giọng Bắc 50-60 tuổi": "Northern Vietnamese accent, resonant, stable, authoritative",
    "Giọng Nam 50-60 tuổi": "Southern Vietnamese accent, resonant, stable, authoritative",
    "Giọng Bắc 60-80 tuổi": "Northern Vietnamese accent, raspy, hearty, rustic",
    "Giọng Nam 60-80 tuổi": "Southern Vietnamese accent, raspy, hearty, rustic"
  };
  return mapping[voiceLabel] || voiceLabel;
};

export const generateNonFaceScript = async (
  imageParts: any[], productName: string, keyword: string, scriptLayout: string, 
  gender: string, voice: string, addressing: string, sceneCount: number, targetAudience: string
): Promise<ScriptParts> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `
    Bạn là chuyên gia marketing Giày dép. Hãy tạo kịch bản Voice-over cho sản phẩm "${productName}". 
    USP: "${keyword}". Layout: "${scriptLayout}". 
    Đặc điểm giọng đọc: ${voice} (${voiceDetail}). Tệp khách hàng: "${targetAudience || 'Đại chúng'}".

    YÊU CẦU: Chia thành đúng ${sceneCount} phần (v1..v${sceneCount}).
    ĐỘ DÀI: 160-190 ký tự mỗi phần. XƯNG HÔ: "${addressing}".
    Tập trung vào cảm giác đi êm chân, form dáng đẹp, phối đồ sang xịn.
    Không dùng từ cấm: ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: { responseMimeType: "application/json", responseSchema: { type: Type.OBJECT, properties, required } }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    return {};
  }
};

export const regenerateNonFaceScriptPart = async (
