      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 p-8 mb-8">
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 border-b pb-6 gap-4">
           <div>
              <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter">Review Giày Dép AI</h2>
              <span className="bg-indigo-100 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mt-1 inline-block">CHÂN THỰC TUYỆT ĐỐI</span>
