                  <input type="file" multiple ref={productInputRef} onChange={handleProductFilesChange} className="hidden" accept="image/*" />
                </div>
                {state.productPreviewUrls.length > 0 && (
                  <div className="grid grid-cols-3 gap-2 mt-2">
                    {state.productPreviewUrls.map((url: string, idx: number) => (
                      <div key={idx} className="relative aspect-[3/4] rounded-lg overflow-hidden border border-slate-200 group shadow-sm">
                        <img src={url} className="w-full h-full object-cover" />
                        <button 
                          onClick={(e) => { e.stopPropagation(); removeProductFile(idx); }}
                          className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full shadow-lg z-10 transition-all hover:scale-110"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12"/></svg>
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* 2. Ảnh chân mẫu - Thu gọn giống ảnh sản phẩm */}
              <div className="space-y-2">
                <label className={`block text-[11px] font-black text-slate-500 uppercase tracking-widest px-1`}>2. Bàn chân mẫu (Ref)</label>
                <div onClick={() => footInputRef.current?.click()} className={`w-full aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-blue-400 transition-all group overflow-hidden relative`}>
                    {state.footPreviewUrl ? (
                      <div className="w-full h-full relative">
                        <img src={state.footPreviewUrl} className="w-full h-full object-cover" />
                        <button onClick={(e) => { e.stopPropagation(); setState((p:any)=>({...p, footFile: null, footPreviewUrl: null})); }} className="absolute top-2 right-2 bg-red-600 text-white p-1 rounded-full shadow-lg z-10"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                      </div>
                    ) : (
                      <div className="text-center opacity-40 group-hover:opacity-60">
                        <svg className="w-8 h-8 mx-auto text-blue-500 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" /></svg>
                        <span className="text-[9px] font-black uppercase tracking-tighter">Tải mẫu chân</span>
                      </div>
                    )}
                  <input type="file" ref={footInputRef} onChange={(e) => { if (e.target.files?.[0]) { const f = e.target.files[0]; setState((p:any) => ({ ...p, footFile: f, footPreviewUrl: URL.createObjectURL(f) })); } }} className="hidden" accept="image/*" />
                </div>
                {state.footPreviewUrl && (
                  <div className="grid grid-cols-3 gap-2 mt-2">
                      <div className="relative aspect-[3/4] rounded-lg overflow-hidden border border-slate-200 group shadow-sm">
                        <img src={state.footPreviewUrl} className="w-full h-full object-cover" />
                        <button 
                          onClick={(e) => { e.stopPropagation(); setState(p => ({ ...p, footFile: null, footPreviewUrl: null })); }}
                          className="absolute top-1 right-1 bg-red-600 text-white p-1 rounded-full shadow-lg z-10 transition-all hover:scale-110"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12"/></svg>
                        </button>
                      </div>
                  </div>
                )}
              </div>
            </div>

            {/* Ô mô tả chân mẫu */}
            <div className="space-y-1">
              <label className="block text-[11px] font-black text-indigo-600 uppercase px-1 tracking-widest">Đặc điểm bàn chân & đôi chân</label>
              <textarea 
                value={state.footDescription} 
                onChange={e => setState((p:any) => ({ ...p, footDescription: e.target.value }))} 
                placeholder="VD: Da trắng, gót hồng, bắp chân thon, đi tất trắng..." 
                className="w-full p-4 border border-slate-200 rounded-[1.5rem] text-xs h-24 resize-none font-bold bg-indigo-50/30 focus:bg-white transition-all outline-none"
              />
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase px-1 tracking-widest">Bối cảnh & Visual Note</label>
              <div className="grid grid-cols-2 gap-4">
                <div onClick={() => backgroundInputRef.current?.click()} className="aspect-square border-2 border-dashed border-slate-200 rounded-[2rem] flex items-center justify-center cursor-pointer bg-slate-50 overflow-hidden relative group hover:border-indigo-400 transition-all">
                  {state.backgroundPreviewUrl ? (
                    <>
                      <img src={state.backgroundPreviewUrl} className="h-full w-full object-cover" />
                      <button onClick={(e) => { e.stopPropagation(); setState((p:any) => ({ ...p, backgroundFile: null, backgroundPreviewUrl: null })); }} className="absolute top-2 right-2 bg-red-600 text-white p-1.5 rounded-full shadow-lg z-10 opacity-0 group-hover:opacity-100 transition-opacity"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </>
                  ) : <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Tải bối cảnh</span>}
                  <input type="file" ref={backgroundInputRef} onChange={(e) => { if (e.target.files?.[0]) { const f = e.target.files[0]; setState((p:any) => ({ ...p, backgroundFile: f, backgroundPreviewUrl: URL.createObjectURL(f) })); } }} className="hidden" accept="image/*" />
                </div>
                <textarea value={state.scriptNote} onChange={e => setState((p:any) => ({ ...p, scriptNote: e.target.value }))} placeholder="Mô tả bối cảnh..." className="w-full p-4 border border-slate-200 rounded-[2rem] text-xs h-full resize-none font-bold bg-slate-50 focus:bg-white transition-all outline-none" />
              </div>
            </div>
          </div>

          <div className="md:col-span-7 space-y-4">
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[11px] font-black text-slate-500 uppercase px-1 tracking-widest">Tên sản phẩm</label>
                <input type="text" value={state.productName} onChange={e => setState((p:any) => ({ ...p, productName: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-orange-100 outline-none" placeholder="VD: Giày Sneaker cao cấp..." />
              </div>
              <div className="space-y-1">
                <label className="block text-[11px] font-black text-orange-600 uppercase px-1 tracking-widest">Tệp khách hàng mục tiêu</label>
                <input type="text" value={state.targetAudience} onChange={e => setState((p:any) => ({ ...p, targetAudience: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold focus:ring-2 focus:ring-orange-100 outline-none" placeholder="VD: Nam giới 25-40 tuổi..." />
              </div>
            </div>
            <div className="space-y-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase px-1 tracking-widest">USP nổi bật (Keyword)</label>
              <textarea value={state.keyword} onChange={e => setState((p:any) => ({ ...p, keyword: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl h-20 text-sm font-bold focus:ring-2 focus:ring-orange-100 outline-none" placeholder="VD: Đế cao su non, da bò thật, chống thấm nước..." />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[11px] font-black text-slate-500 uppercase px-1">Giới tính Người mẫu</label>
                <select value={state.gender} onChange={e => setState((p:any) => ({ ...p, gender: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none">
                  <option value="Nữ">Nữ</option>
                  <option value="Nam">Nam</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="block text-[11px] font-black text-slate-500 uppercase px-1">Giọng vùng miền (VO)</label>
                <select value={state.voice} onChange={e => setState((p:any) => ({ ...p, voice: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold outline-none">
                  {VOICE_OPTIONS.map(v => <option key={v} value={v}>{v}</option>)}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-4">
               <div className="space-y-1">
                <label className="block text-[11px] font-black text-slate-500 uppercase px-1">Phong cách ảnh</label>
                <div className="flex bg-slate-50 p-1.5 rounded-2xl border border-slate-200 shadow-inner">
                  <button onClick={() => setState((p: any) => ({ ...p, imageStyle: 'Realistic' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === 'Realistic' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Real</button>
                  <button onClick={() => setState((p: any) => ({ ...p, imageStyle: '3D' }))} className={`flex-1 py-2 text-[10px] font-black uppercase rounded-xl transition-all ${state.imageStyle === '3D' ? 'bg-orange-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>3D</button>
                </div>
              </div>
              <div className="space-y-1">
                <label className="block text-[11px] font-black text-slate-500 uppercase px-1">Chế độ hiển thị</label>
                <select value={state.displayMode} onChange={e => setState((p:any) => ({ ...p, displayMode: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-indigo-600 outline-none">
                  <option value="on_foot">Đang đi vào chân (Wearing)</option>
                  <option value="beside_foot">Đặt cạnh chân (Beside)</option>
                  <option value="no_foot">Chỉ sản phẩm (Product only)</option>
                </select>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[11px] font-black text-slate-500 uppercase px-1 tracking-widest">Bố cục kịch bản (Layout)</label>
              <select value={state.scriptLayout} onChange={e => setState((p:any) => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none focus:ring-2 focus:ring-orange-100 transition-all">
                <option value="">-- Random Layout --</option>
                {LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            </div>

            <div className="grid grid-cols-2 gap-4">
