                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">2. Bàn chân mẫu (Ref)</label>
                <div onClick={() => footInputRef.current?.click()} className={`w-full aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-blue-400 transition-all group overflow-hidden relative`}>
                    {state.footPreviewUrl ? (
                      <div className="w-full h-full relative group/foot">
                        <img src={state.footPreviewUrl} className="w-full h-full object-cover" />
                        <button 
                          onClick={(e) => { e.stopPropagation(); setState((p:any)=>({...p, footFile: null, footPreviewUrl: null})); }} 
                          className="absolute top-2 right-2 bg-red-600/80 text-white p-1 rounded-full opacity-0 group-hover/foot:opacity-100 transition-all"
                        >
                          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
