                <input type="text" value={state.productName} onChange={e => setState((p:any) => ({ ...p, productName: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-bold focus:ring-2 focus:ring-orange-100 outline-none" placeholder="VD: Giày Sneaker cao cấp..." />
