                <input list="nf2-addr" value={state.addressing} onChange={e => setState((p:any) => ({ ...p, addressing: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-sm outline-none focus:ring-2 focus:ring-orange-100" placeholder="VD: em - anh chị" />
                <datalist id="nf2-addr">{ADDRESSING_OPTIONS.map(o => <option key={o} value={o} />)}</datalist>
