                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Chế độ hiển thị</label>
                <select value={state.displayMode} onChange={e => setState((p:any) => ({ ...p, displayMode: e.target.value }))} className="w-full p-4 bg-white border border-slate-200 rounded-2xl font-bold text-indigo-600 outline-none">
