                TỰ ĐỘNG TẠO TẤT CẢ ẢNH
                <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V5a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" clipRule="evenodd" /></svg>
              </button>
              <button
                onClick={() => handleBulkAction('prompt')}
                className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-2xl hover:scale-105 active:scale-95 transition-all text-lg flex items-center justify-center gap-4 uppercase tracking-widest"
              >
