              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-orange-600 uppercase px-1">Tệp khách hàng mục tiêu</label>
                <input type="text" value={state.targetAudience} onChange={e => setState((p:any) => ({ ...p, targetAudience: e.target.value }))} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-sm font-bold focus:ring-2 focus:ring-orange-100 outline-none" placeholder="VD: Nam giới 25-40 tuổi..." />
