áp dụng các quy tắc dưới đây cho module timelapse:

import { GoogleGenAI, SchemaType } from "@google/genai";
import { getAiClient } from "./keyService";

// ============================================================================
// 1. DEFINITIONS & TYPES
// ============================================================================

/**
 * Cấu trúc dữ liệu lưu trữ ngữ cảnh của quá trình biến đổi.
 * Giúp các hàm sau hiểu được chúng đang làm việc với đối tượng nào.
 */
export interface TimelapseContext {
  subject: string;       // VD: "Phòng ngủ", "Chân dung cô gái", "Cây sồi"
  processType: string;   // VD: "Construction", "Digital Painting", "Plant Growth"
  rawMaterial: string;   // VD: "Bê tông thô", "Nét phác chì", "Hạt mầm"
  toolsVisible: string;  // VD: "Thang & Thùng sơn", "Bút Stylus", "Bình tưới"
}

/**
 * Làm sạch phản hồi JSON từ AI
 */
const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

/**
 * Chuyển đổi File sang định dạng inlineData base64
 */
export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

// ============================================================================
// 2. CORE FUNCTIONS
// ============================================================================

/**
 * BƯỚC 1: PHÂN TÍCH NGỮ CẢNH (CONTEXT ANALYSIS)
 * AI nhìn 2 ảnh và tự định nghĩa quá trình này là gì.
 */
const analyzeTransformationContext = async (
  baseImagePart: any, 
  finalGoalPart: any
): Promise<TimelapseContext> => {
  const ai = getAiClient();
  const prompt = `
    ANALYZE the visual transformation from Image A (Start) to Image B (End).
    Identify the following attributes strictly in JSON format:
    1. "subject": What is the main object? (e.g., Living Room, Anime Character, Forest)
    2. "processType": What specific process is happening? (Choose one best fit: "Construction/Renovation", "Art/Drawing", "Biological Growth", "Restoration", "Generic Transformation")
    3. "rawMaterial": What does the 0-10% stage look like? (e.g., Concrete & Wires, Rough Sketch, Seed)
    4. "toolsVisible": What tools are typically seen during this process? (e.g., Ladders/Paint buckets, Brushes/Pencils, Water can, or None)
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash", // Dùng Flash cho tốc độ phân tích nhanh
      contents: { 
        parts: [
          { text: prompt },
          { inlineData: baseImagePart },
          { inlineData: finalGoalPart }
        ] 
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: SchemaType.OBJECT,
          properties: {
            subject: { type: SchemaType.STRING },
            processType: { type: SchemaType.STRING },
            rawMaterial: { type: SchemaType.STRING },
            toolsVisible: { type: SchemaType.STRING },
          },
          required: ["subject", "processType", "rawMaterial", "toolsVisible"]
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (error) {
    console.warn("Context analysis failed, using default.", error);
    return {
      subject: "Object",
      processType: "Construction", // Fallback an toàn
      rawMaterial: "Unfinished structure",
      toolsVisible: "Tools"
    };
  }
};

/**
 * BƯỚC 2: TẠO KỊCH BẢN (SCRIPT GENERATION)
 * Trả về cả Kịch bản (Script) và Ngữ cảnh (Context) để dùng cho các bước sau.
 */
export const generateTimelapseScript = async (
  baseImagePart: any, 
  finalGoalPart: any, 
  sceneCount: number,
  progressSteps: number[]
): Promise<{ script: string[], context: TimelapseContext }> => {

  // 1. Phân tích ngữ cảnh trước
  const context = await analyzeTransformationContext(baseImagePart, finalGoalPart);

  const ai = getAiClient();
  const prompt = `
    CONTEXT:
    - Subject: ${context.subject}
    - Process: ${context.processType}
    - Raw Start: ${context.rawMaterial}

    TASK: Generate a ${sceneCount}-step visual description for a timelapse video.
    PROGRESS POINTS: ${progressSteps.join('%, ')}%.

    RULES:
    1. Adapt strictly to the "${context.processType}" process.
    2. Early stages (<30%) must focus on ${context.rawMaterial}.
    3. Middle stages (30-80%) must describe the active work/growth involving ${context.toolsVisible}.
    4. Late stages (>80%) focus on refining and detailing.
    5. OUTPUT LANGUAGE: Vietnamese. Concise, descriptive.

    OUTPUT: JSON Array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: SchemaType.ARRAY, items: { type: SchemaType.STRING } }
      }
    });

    return {
      script: JSON.parse(cleanJsonResponse(response.text || '[]')),
      context: context // QUAN TRỌNG: Trả về context để UI lưu lại dùng cho tạo ảnh
    };
  } catch (error) {
    return {
      script: progressSteps.map(p => `Giai đoạn ${p}%: Quá trình biến đổi đang diễn ra...`),
      context: context
    };
  }
};

/**
 * BƯỚC 3: TẠO ẢNH TRUNG GIAN (UNIVERSAL IMAGE GENERATION)
 * Sử dụng Context để quyết định độ "Bừa bộn" và các chi tiết phụ.
 */
export const generateTimelapseImage = async (
  context: TimelapseContext, // <--- Bắt buộc truyền context vào đây
  sceneDescription: string,
  baseImagePart: any,
  finalGoalPart: any,
  progress: number
): Promise<string> => {
  const ai = getAiClient();
  // Khuyên dùng model có khả năng hiểu ảnh tốt nhất (Gemini 2.0 Flash Exp hoặc Imagen 3)
  const modelId = "gemini-2.0-flash-exp"; 

  // Logic: Xác định "Sự bừa bộn" (Messiness) dựa trên loại quá trình
  let messDescription = "";
  const process = context.processType.toLowerCase();

  if (process.includes("construction") || process.includes("renovation") || process.includes("interior")) {
     messDescription = "Construction atmosphere: Dust, debris on floor, paint buckets, ladders. Furniture wrapped in blue plastic sheets.";
  } else if (process.includes("drawing") || process.includes("art") || process.includes("sketch")) {
     messDescription = "Artist workspace: Pencil shavings, paint spills, color palettes, brushes lying around. The artwork looks half-finished.";
  } else if (process.includes("plant") || process.includes("nature") || process.includes("growth")) {
     messDescription = "Nature atmosphere: Soil particles, scattered leaves, water droplets, sunlight rays. Organic texture.";
  } else {
     messDescription = "Work-in-progress state: Unpolished surfaces, visible tools, rough edges.";
  }

  // Prompt kỹ thuật (Technical Prompt)
  const prompt = `
    ROLE: Time-lapse Visual Artist.
    TASK: Generate an intermediate frame at ${progress}% completion for a "${context.processType}" project.
    SUBJECT: ${context.subject}.

    VISUAL RULES (STRICT):
    1. STAGE < 25%: DOMINANCE of Base Material. Show "${context.rawMaterial}". Structure is skeletal/rough.
    2. STAGE 25-85%: THE "UGLY" PHASE.
       - MUST SHOW: ${messDescription}
       - MUST SHOW: "${context.toolsVisible}" interacting with the scene.
       - The object MUST look unfinished (e.g., unpainted, lacking detail, covered in protective layers).
    3. STAGE > 85%: Cleaning up. Tools removed. Polishing phase.

    CONSTRAINT:
    - Keep Camera Perspective IDENTICAL to the Goal Image.
    - NO TEXT, NO LOGOS.
    - Photorealistic (unless context is specific art style).

    SCENE DESCRIPTION: "${sceneDescription}"
  `;

  // Chiến thuật Input ảnh: 
  // - Giai đoạn đầu (<30%): Cần cả ảnh Base để giữ kết cấu thô.
  // - Giai đoạn sau (>30%): Chỉ cần ảnh Goal để lấy khung hình chuẩn, prompt sẽ lo phần "làm xấu".
  let contents: any[] = [{ text: prompt }];
  if (progress < 30) {
     contents.push({ inlineData: baseImagePart });
     contents.push({ inlineData: finalGoalPart }); 
  } else {
     contents.push({ inlineData: finalGoalPart });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("AI không trả về hình ảnh.");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) {
    console.error("Image Gen Error:", error);
    throw error;
  }
};

/**
 * BƯỚC 4: TẠO VIDEO PROMPT (UNIVERSAL ACTION)
 * Xác định hành động (Action) dựa trên ngữ cảnh.
 */
export const generateTimelapseVideoPrompt = async (
  context: TimelapseContext, // <--- Bắt buộc truyền context vào đây
  description: string,
  imageUrl: string,
  progress: number
): Promise<string> => {
  const ai = getAiClient();
  const process = context.processType.toLowerCase();

  // Logic: Xác định "Diễn viên" (Actor) và "Hành động" (Action)
  let actionPrompt = "";

  if (["construction", "renovation", "interior", "decor"].some(k => process.includes(k))) {
      // Xây dựng -> Cần công nhân
      if (progress < 90) {
        actionPrompt = "Include 1 worker in casual work clothes moving tools or materials. Fast-forward style movement. Busy atmosphere.";
      } else {
        actionPrompt = "Cinematic slow pan revealing the finished room. No people. Ambient lighting on.";
      }
  } 
  else if (["drawing", "painting", "art", "sketch", "digital"].some(k => process.includes(k))) {
      // Vẽ tranh -> Cần bàn tay
      actionPrompt = `Close-up shot. A hand holding ${context.toolsVisible} is actively working on the details. Fast artistic strokes.`;
  }
  else if (["plant", "growth", "flower", "nature", "bio"].some(k => process.includes(k))) {
      // Cây cối -> Tự lớn (Organic)
      actionPrompt = "Organic time-lapse movement. The object is slightly pulsing or growing. Shadows from the sun move quickly across the frame.";
  }
  else {
      // Mặc định -> Chuyển động chung
      actionPrompt = "Time-lapse style movement. Lighting shifts rapidly. Objects evolve naturally.";
  }

  const prompt = `
    Generate a precise VEO-3 video generation prompt (English).
    SCENE: ${description}.
    CONTEXT: ${context.processType} of ${context.subject}.
    PROGRESS: ${progress}%.

    MANDATORY ACTION: ${actionPrompt}

    STYLE: 4K, 60fps, Photorealistic.
    OUTPUT: Return ONLY the raw prompt string.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: { 
        parts: [
          { text: prompt },
          { inlineData: { mimeType: 'image/png', data: imageUrl.split(',')[1] } }
        ] 
      }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return `Timelapse video of ${context.subject}, ${progress}%, 4k realistic.`;
  }
};

