import { GoogleGenAI, Type } from "@google/genai";
import { getAiClient } from "./keyService";
import { TimelapseContext } from "../types";

/**
 * Làm sạch phản hồi JSON từ mô hình AI bằng cách loại bỏ các thẻ markdown.
 */
const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

/**
 * Helper: Chuyển đổi File sang định dạng inlineData base64 để AI có thể xử lý hình ảnh.
 */
export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * BƯỚC 1: Phân tích sự biến đổi từ Ảnh A (Bắt đầu) sang Ảnh B (Kết thúc) để xác định loại dự án.
 */
const analyzeTransformationContext = async (
  baseImagePart: any, 
  finalGoalPart: any
): Promise<TimelapseContext> => {
  const ai = getAiClient();
  const prompt = `
    HÃY PHÂN TÍCH sự biến đổi từ Hình A (Bắt đầu) sang Hình B (Kết thúc).
    Xác định các thuộc tính sau và trả về ở định dạng JSON:
    1. "subject": Đối tượng chính là gì? (VD: Phòng khách, Nhân vật Anime, Khu rừng, Tòa nhà)
    2. "processType": Đây là loại quá trình gì? (VD: Thi công nội thất, Vẽ tranh kỹ thuật số, Sự phát triển sinh học, Sự hoen gỉ/phân hủy)
    3. "rawMaterial": Giai đoạn 0-10% trông như thế nào? (VD: Bê tông và dây điện, Nét vẽ phác thảo, Mầm cây nhỏ)
    4. "toolsVisible": Những công cụ nào có thể xuất hiện trong quá trình? (VD: Thang/Thùng sơn, Bút vẽ, Bình tưới nước, hoặc Không có)
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { 
        parts: [
          { text: prompt },
          { inlineData: baseImagePart },
          { inlineData: finalGoalPart }
        ] 
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            subject: { type: Type.STRING },
            processType: { type: Type.STRING },
            rawMaterial: { type: Type.STRING },
            toolsVisible: { type: Type.STRING },
          },
          required: ["subject", "processType", "rawMaterial", "toolsVisible"]
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (error) {
    return {
      subject: "Đối tượng",
      processType: "Sự biến đổi",
      rawMaterial: "Trạng thái ban đầu",
      toolsVisible: "Không rõ"
    };
  }
};

/**
 * BƯỚC 2: Tạo kịch bản dựa trên Ngữ cảnh đã phân tích.
 */
export const generateTimelapseScript = async (
  baseImagePart: any, 
  finalGoalPart: any, 
  sceneCount: number,
  progressSteps: number[]
): Promise<{ script: string[], context: TimelapseContext }> => {
  const context = await analyzeTransformationContext(baseImagePart, finalGoalPart);
  const ai = getAiClient();

  const prompt = `
    NGỮ CẢNH:
    - Chủ thể: ${context.subject}
    - Quá trình: ${context.processType}
    - Vật liệu thô ban đầu: ${context.rawMaterial}

    NHIỆM VỤ: Tạo mô tả ${sceneCount} bước cho một video timelapse dựa trên các mốc tiến độ sau: ${progressSteps.join('%, ')}%.

    QUY TẮC:
    1. Thích ứng nghiêm ngặt theo quy trình "${context.processType}".
    2. Các giai đoạn đầu (20%) phải tập trung vào ${context.rawMaterial} (cấu trúc/phác thảo/nền móng/hạt mầm).
    3. Các giai đoạn giữa (20-50%) phải tập trung vào việc xây dựng/bồi đắp/phát triển/hành trình và sự xuất hiện của ${context.toolsVisible}.
    3. Các giai đoạn giữa (50-80%) phải tập trung vào vào việc tinh chỉnh/đánh bóng/hoàn thiện/cây cối hình thành ${context.toolsVisible}.
    4. Các giai đoạn cuối (>80%) tập trung vào việc dọn dẹp sạch sẽ/trang trí/điện/ánh sáng.
    5. Ngôn ngữ đầu ra: Tiếng Việt. Mô tả trạng thái vật lý, không dùng từ hoa mỹ.

    OUTPUT: Mảng JSON chứa các chuỗi ký tự mô tả trạng thái hình ảnh.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return {
      script: JSON.parse(cleanJsonResponse(response.text || '[]')),
      context: context
    };
  } catch (error) {
    return {
      script: progressSteps.map(p => `Giai đoạn thi công/biến đổi đạt ${p}%`),
      context: context
    };
  }
};

/**
 * BƯỚC 3: Tạo ảnh trung gian bám sát Ngữ cảnh.
 */
export const generateTimelapseImage = async (
  context: TimelapseContext,
  sceneDescription: string,
  baseImagePart: any,
  finalGoalPart: any,
  progress: number
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";

  const prompt = `
    VAI TRÒ: Nghệ sĩ thị giác Time-lapse.
    NHIỆM VỤ: Tạo một khung hình trung gian thực tế cho video timelapse về "${context.processType}" của một "${context.subject}".
    TIẾN ĐỘ: ${progress}%.

    QUY TẮC THỊ GIÁC (Áp dụng nghiêm ngặt cho ${context.processType}):

    1. ĐỊNH NGHĨA GIAI ĐOẠN:
       - Nếu Tiến độ < 20%: Chỉ hiển thị "${context.rawMaterial}". (VD: nếu là vẽ: chỉ có nét phác; nếu là xây dựng: chỉ có nền móng thô; nếu là cây cối: chỉ có hạt mầm...).
       - Nếu Tiến độ < 30%: Trạng thái đang thực hiện. Hiển thị "${context.toolsVisible}" đang tương tác với chủ thể. tường đã sơn, hoàn thiện sàn, đồ đạc còn sắp xếp lung tung và được boc nilon, hoàn thiện phác thảo, đường, nền.
       - Nếu Tiến độ < 50%: Trạng thái đang thực hiện. Hiển thị "${context.toolsVisible}" đang tương tác với chủ thể. Các thành phần chưa hoàn thiện, đã sơn, hoàn thiện tường, đồ đạc còn sắp xếp lung tung và được boc nilon.
       - Nếu Tiến độ < 80%: Trạng thái đang thực hiện. Hiển thị "${context.toolsVisible}" đang tương tác với chủ thể. Các thành phần còn lại chưa hoàn thiện, đồ đạc còn sắp xếp lung tung và được boc nilon 
       - Nếu Tiến độ < 100%: Gần hoàn thiện. Thiếu độ bóng, bề mặt còn bụi, hoặc còn các lớp bảo vệ/giàn giáo;nếu là cây thì chưa có quả, nếu là tranh thì chưa tô màu hoàn thiện.

    2. CẢM GIÁC CHƯA HOÀN THIỆN (Bắt buộc):
       - Hình ảnh KHÔNG ĐƯỢC trông giống kết quả cuối cùng. 
       - Phải trông giống như "Đang xây dựng" hoặc "Đang sáng tạo" hoặc "đang phát triển".
       - Thêm sự bừa bộn có tính ngữ cảnh (bụi bặm cho xây dựng, vụn bút chì cho hội họa, đất cát cho cây trồng, bùn đất cho công trường).

    3. TÍNH NHẤT QUÁN:
       - Giữ nguyên bố cục và góc máy của Ảnh Kết Thúc (Goal Image).
       - Sử dụng bảng màu và vật liệu từ Ảnh Bắt Đầu (Base Image) cho các giai đoạn sớm.
       - Không xuất hiện người trong ảnh.

    NGỮ CẢNH CẢNH QUAY: "${sceneDescription}"
    PHONG CÁCH: 4k, Ảnh thực (Photorealistic). Tuyệt đối KHÔNG CÓ CHỮ, KHÔNG LOGO.
  `;

  const contents: any[] = [{ text: prompt }];

  if (progress < 30) {
     contents.push({ inlineData: baseImagePart });
     contents.push({ inlineData: finalGoalPart }); 
  } else {
     contents.push({ inlineData: finalGoalPart });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("Không thể tạo hình ảnh");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) {
    console.error("Lỗi tạo ảnh AI:", error);
    throw error;
  }
};

/**
 * BƯỚC 4: Tạo video prompt cho VEO-3 dựa trên các quy tắc hành động và chuyển động camera cụ thể.
 */
export const generateTimelapseVideoPrompt = async (
  description: string,
  imageUrl: string,
  progress: number
): Promise<string> => {
  const ai = getAiClient();

  let specificInstruction = "";
  if (progress === 0) {
    // Logic cho cảnh hiện trạng (0%)
    specificInstruction = `
      MANDATORY ACTION: The scene focuses on SITE CLEANUP AND RENOVATION.
      - Show 1 person actively clearing debris, sweeping a dusty floor, and moving old materials.
      - Fine dust particles are visible in the air, catching the sunlight.
      - The environment looks raw, skeletal, and empty.
      - CAMERA: 100% fixed on a tripod (static tripod shot).
    `;
  } else if (progress === 100) {
    // Logic cho cảnh kết quả (100%)
    specificInstruction = `
      MANDATORY ACTION: A CINEMATIC REVEAL of the finished space.
      - No workers present.
      - CAMERA MOVEMENT: The camera moves SEAMLESSLY and SLOWLY in one continuous 8-second motion.
      - Use a combination of a slow pan and a subtle push-in to showcase the perfect textures, materials, and lighting of the interior design.
      - Show glowing lights and active screens as per the final design.
    `;
  } else {
    // Logic cho các giai đoạn thi công trung gian
    specificInstruction = `
      MANDATORY ACTION: Include 1 person dressed in casual work clothes.
      - They are busy working, cleaning, painting, moving a single piece of furniture into place, or removing protective plastic sheets.
      - The room is cluttered with tools and protective tarps.
      - ABSOLUTELY NO MAGIC APPEARANCE: Furniture must not simply "fly" into the frame.
      - CAMERA: 100% fixed and LOCKED (Tripod shot). NO pan, NO zoom.
    `;
  }

  const prompt = `
    Generate a detailed VEO-3 video prompt for a realistic 8-second timelapse scene.
    SCENE DESCRIPTION: ${description}.
    PROGRESS: ${progress}% complete.

    ${specificInstruction}

    STRICT CONSTRAINT: NO SPECIAL EFFECTS. No magic animations, no neon trails.
    ATMOSPHERE: High-end architectural magazine realism. Professional lighting.

    TECHNICAL SPECS: 9:16 aspect ratio, 4K resolution, 60fps, photorealistic.
    OUTPUT REQUIREMENT: Return ONLY 1 single line in English for the video model. No labels, no titles.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { 
        parts: [
          { text: prompt },
          { inlineData: { mimeType: 'image/png', data: imageUrl.split(',')[1] } }
        ] 
      }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    console.error("Lỗi tạo video prompt:", error);
    return `Cinematic shot of ${progress}% construction progress, 4k.`;
  }
};

