export const generateTimelapseScript = async (
  baseImagePart: any, 
  finalGoalPart: any, 
  sceneCount: number,
  progressSteps: number[]
): Promise<{ script: string[], context: TimelapseContext }> => {
  const context = await analyzeTransformationContext(baseImagePart, finalGoalPart);
  const ai = getAiClient();

  const prompt = `
    NGỮ CẢNH:
    - Chủ thể: ${context.subject}
    - Quá trình: ${context.processType}
    - Vật liệu thô ban đầu: ${context.rawMaterial}

    NHIỆM VỤ: Tạo mô tả ${sceneCount} bước cho một video timelapse dựa trên các mốc tiến độ sau: ${progressSteps.join('%, ')}%.

    QUY TẮC:
    1. Thích ứng nghiêm ngặt theo quy trình "${context.processType}".
    2. Các giai đoạn đầu (<30%) phải tập trung vào ${context.rawMaterial} (cấu trúc/phác thảo/nền móng/hạt mầm).
    3. Các giai đoạn giữa (30-80%) phải mô tả việc xây dựng/bồi đắp có sự xuất hiện của ${context.toolsVisible}.
    4. Các giai đoạn cuối (>80%) tập trung vào hoàn thiện/dọn dẹp/ánh sáng.
    5. Ngôn ngữ đầu ra: Tiếng Việt. Mô tả trạng thái vật lý chân thực.

    OUTPUT: Mảng JSON chứa các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return {
      script: JSON.parse(cleanJsonResponse(response.text || '[]')),
      context: context
    };
  } catch (error) {
    return {
      script: progressSteps.map(p => `Giai đoạn thi công/biến đổi đạt ${p}%`),
      context: context
    };
  }
};

/**
 * BƯỚC 3: TẠO ẢNH TRUNG GIAN (UNIVERSAL IMAGE GENERATION)
 */
export const generateTimelapseImage = async (
  context: TimelapseContext,
  sceneDescription: string,
  baseImagePart: any,
  finalGoalPart: any,
  progress: number
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";

  let messDescription = "";
  const process = context.processType.toLowerCase();

  if (process.includes("construction") || process.includes("renovation") || process.includes("interior")) {
     messDescription = "Không gian thi công: Bụi, mảnh vụn trên sàn, thùng sơn, thang. Nội thất được bọc nilon bảo vệ.";
  } else if (process.includes("drawing") || process.includes("art") || process.includes("sketch")) {
     messDescription = "Không gian họa sĩ: Vụn bút chì, vết sơn loang, bảng màu, cọ vẽ để bừa bộn. Bức tranh mới hoàn thiện một phần.";
  } else if (process.includes("plant") || process.includes("nature") || process.includes("growth")) {
     messDescription = "Môi trường tự nhiên: Các hạt đất, lá rụng, giọt nước, tia nắng xuyên qua. Kết cấu hữu cơ.";
  } else {
     messDescription = "Trạng thái đang thực hiện: Bề mặt chưa đánh bóng, công cụ xuất hiện, các cạnh thô ráp.";
  }

  const prompt = `
    VAI TRÒ: Nghệ sĩ thị giác Time-lapse.
    NHIỆM VỤ: Tạo một khung hình trung gian thực tế cho video timelapse về "${context.processType}" của một "${context.subject}".
    TIẾN ĐỘ: ${progress}%.

    QUY TẮC THỊ GIÁC (Áp dụng nghiêm ngặt cho ${context.processType}):

    1. ĐỊNH NGHĨA GIAI ĐOẠN:
       - Nếu Tiến độ < 25%: Chủ yếu là vật liệu thô. Hiển thị "${context.rawMaterial}". Cấu trúc bộ khung thô sơ.
       - Nếu Tiến độ 25-85%: GIAI ĐOẠN "BỪA BỘN".
         - BẮT BUỘC: ${messDescription}
         - BẮT BUỘC: "${context.toolsVisible}" đang tương tác với cảnh.
         - Đối tượng PHẢI trông chưa hoàn thiện (chưa sơn xong, thiếu chi tiết, bám bụi).
       - Nếu Tiến độ > 85%: Giai đoạn dọn dẹp và đánh bóng. Công cụ dần được loại bỏ.

    2. TÍNH NHẤT QUÁN:
       - Giữ nguyên bố cục và góc máy của Ảnh Kết Thúc (Goal Image).
       - Tuyệt đối không xuất hiện người trong ảnh.
       - NO TEXT, NO LOGOS.

    MÔ TẢ CẢNH QUAY: "${sceneDescription}"
    PHONG CÁCH: 4k, Ảnh thực (Photorealistic).
  `;

  const contents: any[] = [{ text: prompt }];

  if (progress < 30) {
     contents.push({ inlineData: baseImagePart });
     contents.push({ inlineData: finalGoalPart }); 
  } else {
     contents.push({ inlineData: finalGoalPart });
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("Không thể tạo hình ảnh");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) {
    throw error;
  }
};

/**
 * BƯỚC 4: TẠO VIDEO PROMPT (UNIVERSAL ACTION)
 */
export const generateTimelapseVideoPrompt = async (
  context: TimelapseContext,
  description: string,
  imageUrl: string,
  progress: number
): Promise<string> => {
  const ai = getAiClient();
  const process = context.processType.toLowerCase();

  let actionPrompt = "";

  if (["construction", "renovation", "interior", "decor"].some(k => process.includes(k))) {
      if (progress < 90) {
        actionPrompt = "Include 1 worker in casual work clothes moving tools or materials. Fast-forward style movement. Busy atmosphere.";
      } else {
        actionPrompt = "Cinematic slow pan revealing the finished room. No people. Ambient lighting on.";
      }
  } 
  else if (["drawing", "painting", "art", "sketch", "digital"].some(k => process.includes(k))) {
      actionPrompt = `Close-up shot. A hand holding ${context.toolsVisible} is actively working on the details. Fast artistic strokes.`;
  }
  else if (["plant", "growth", "flower", "nature", "bio"].some(k => process.includes(k))) {
      actionPrompt = "Organic time-lapse movement. The object is slightly pulsing or growing. Shadows from the sun move quickly across the frame.";
  }
  else {
      actionPrompt = "Time-lapse style movement. Lighting shifts rapidly. Objects evolve naturally.";
  }

  const prompt = `
    Generate a precise VEO-3 video generation prompt (English).
    SCENE: ${description}.
    CONTEXT: ${context.processType} of ${context.subject}.
    PROGRESS: ${progress}%.

    MANDATORY ACTION: ${actionPrompt}

    STYLE: 4K, 60fps, Photorealistic.
    OUTPUT: Return ONLY the raw prompt string.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { 
        parts: [
          { text: prompt },
          { inlineData: { mimeType: 'image/png', data: imageUrl.split(',')[1] } }
        ] 
      }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return `Timelapse video of ${context.subject}, ${progress}%, 4k realistic.`;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import * as service from '../services/timelapseService';
import { TimelapseSegment, TimelapseContext } from '../types';

declare var JSZip: any;

const DURATION_OPTIONS = [
  { scenes: 3, label: '3 cảnh - 24s' },
  { scenes: 4, label: '4 cảnh - 32s' },
  { scenes: 5, label: '5 cảnh - 40s' },
  { scenes: 6, label: '6 cảnh - 48s' },
  { scenes: 7, label: '7 cảnh - 56s' },
  { scenes: 8, label: '8 cảnh - 64s' },
];

const getProgressArray = (count: number): number[] => {
  if (count <= 1) return [0];
  if (count === 2) return [0, 100];
  const result = [0, 20];
  const remainingScenes = count - 2;
  const totalRemainingProgress = 80;
  const stepSize = totalRemainingProgress / remainingScenes;
  for (let i = 1; i < remainingScenes; i++) {
    result.push(Math.round(20 + i * stepSize));
  }
  result.push(100);
  return result;
};

const TimelapseModule: React.FC = () => {
  const storageKey = "timelapse_project_v15_context_aware";
  const [baseFile, setBaseFile] = useState<File | null>(null);
  const [basePreview, setBasePreview] = useState<string | null>(null);
  const [finalFile, setFinalFile] = useState<File | null>(null);
  const [finalPreview, setFinalPreview] = useState<string | null>(null);
  const [sceneCount, setSceneCount] = useState(4);
  const [isProcessing, setIsProcessing] = useState(false);
  const [context, setContext] = useState<TimelapseContext | null>(null);
  const [segments, setSegments] = useState<TimelapseSegment[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const finalInputRef = useRef<HTMLInputElement>(null);
  const jsonImportRef = useRef<HTMLInputElement>(null);
  const segmentUploadRef = useRef<HTMLInputElement>(null);
  const [uploadingSegmentId, setUploadingSegmentId] = useState<number | null>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        setSceneCount(parsed.sceneCount || 4);
        setBasePreview(parsed.basePreview || null);
        setFinalPreview(parsed.finalPreview || null);
        setContext(parsed.context || null);
        setSegments((parsed.segments || []).map((s: any) => ({
          ...s,
          image: { ...s.image, url: s.image.url || '', loading: false },
          videoPrompt: { ...s.videoPrompt, loading: false }
        })));
      }
    } catch (e) {}
  }, []);

  useEffect(() => {
    try {
      const toSave = {
        sceneCount,
        context,
        basePreview: basePreview?.startsWith('data:') ? basePreview : '',
        finalPreview: finalPreview?.startsWith('data:') ? finalPreview : '',
        segments: segments.map(s => ({
          ...s,
          image: { ...s.image, url: s.image.url?.startsWith('data:') ? s.image.url : '' },
          videoPrompt: { ...s.videoPrompt, loading: false }
        }))
      };
      localStorage.setItem(storageKey, JSON.stringify(toSave));
    } catch (e) {}
  }, [sceneCount, basePreview, finalPreview, segments, context]);

  const processImportData = async (importedData: any) => {
    if (!Array.isArray(importedData) || importedData.length === 0) return;
    window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 5, complete: false } }));
    try {
      const first = importedData[0].inputs || {};
      setSceneCount(first.sceneCount || importedData.length);
      setBasePreview(first.basePreview || "");
      setFinalPreview(first.finalPreview || "");
      setContext(first.context || null);

      const newSegments: TimelapseSegment[] = [];
      const total = importedData.length;
      for (let i = 0; i < total; i++) {
        const item = importedData[i];
        newSegments.push({
          id: i + 1,
          content: item.script || '',
          image: { url: item.outputImage || '', loading: false, regenNote: '' },
          videoPrompt: { text: item.videoPrompt || '', loading: false, visible: !!item.videoPrompt }
        });
        const percent = Math.round(((i + 1) / total) * 100);
        window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: Math.min(percent, 95), complete: false } }));
        await new Promise(r => setTimeout(r, 30));
      }
      setSegments(newSegments);
      window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 100, complete: true } }));
    } catch (err) {
      window.dispatchEvent(new CustomEvent('IMPORT_DATA_PROGRESS', { detail: { percent: 100, complete: true } }));
    }
  };

  useEffect(() => {
    const handleGlobalExport = () => {
        if (segments.length === 0) return;
        const exportData = segments.map((seg, index) => ({
          stt: index + 1,
          inputs: { sceneCount, basePreview, finalPreview, context },
          script: seg.content,
          outputImage: seg.image.url || '',
          videoPrompt: seg.videoPrompt.text || ''
        }));
        window.dispatchEvent(new CustomEvent('EXPORT_DATA_READY', { 
          detail: { data: exportData, moduleName: 'Timelapse_Context_Aware' } 
        }));
    };
    const handleGlobalImport = (e: any) => processImportData(e.detail);
    window.addEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
    window.addEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    return () => {
      window.removeEventListener('REQUEST_EXPORT_DATA', handleGlobalExport);
      window.removeEventListener('REQUEST_IMPORT_DATA', handleGlobalImport);
    };
  }, [segments, sceneCount, basePreview, finalPreview, context]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setBaseFile(file);
      setBasePreview(URL.createObjectURL(file));
    }
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFinalFile(file);
      setFinalPreview(URL.createObjectURL(file));
    }
  };

  const handleStart = async () => {
    if (!basePreview || !finalPreview) {
      alert("Cần ảnh HIỆN TRẠNG và ảnh KẾT QUẢ.");
      return;
    }
    setIsProcessing(true);
    try {
      const getPart = async (file: File | null, preview: string | null) => {
        if (file) return await service.fileToGenerativePart(file);
        if (preview?.startsWith('data:')) return { mimeType: 'image/png', data: preview.split(',')[1] };
        return null;
      };
      const basePart = await getPart(baseFile, basePreview);
      const finalPart = await getPart(finalFile, finalPreview);
      const progressSteps = getProgressArray(sceneCount);

      const { script, context: analyzedContext } = await service.generateTimelapseScript(basePart, finalPart, sceneCount, progressSteps);

      setContext(analyzedContext);
      const newSegments: TimelapseSegment[] = script.map((desc, i) => ({
        id: i + 1,
        content: desc,
        image: { 
          url: i === 0 ? basePreview : (i === sceneCount - 1 ? finalPreview : ''), 
          loading: false,
          regenNote: ''
        },
        videoPrompt: { text: '', loading: false, visible: false }
      }));
      setSegments(newSegments);
    } catch (e) { console.error(e); } finally { setIsProcessing(false); }
  };

  const handleGenImage = async (id: number) => {
    if (!context) return;
    const idx = id - 1;
    setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: true } } : s));
    try {
      const getPart = async (file: File | null, preview: string | null) => {
        if (file) return await service.fileToGenerativePart(file);
        if (preview?.startsWith('data:')) return { mimeType: 'image/png', data: preview.split(',')[1] };
        return null;
      };
      const basePart = await getPart(baseFile, basePreview);
      const finalPart = await getPart(finalFile, finalPreview);
      const progressSteps = getProgressArray(segments.length);
      const url = await service.generateTimelapseImage(context, segments[idx].content, basePart, finalPart, progressSteps[idx]);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, url, loading: false } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, image: { ...s.image, loading: false, error: 'Lỗi' } } : s));
    }
  };

  const handleBulkImage = async () => {
    for (const seg of segments) {
      if (!seg.image.url) await handleGenImage(seg.id);
    }
  };

  const handleGenPrompt = async (id: number) => {
    if (!context) return;
    const idx = id - 1;
    const seg = segments[idx];
    if (!seg.image.url) return;
    setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: true, visible: true } } : s));
    try {
      const progressSteps = getProgressArray(segments.length);
      const prompt = await service.generateTimelapseVideoPrompt(context, seg.content, seg.image.url, progressSteps[idx]);
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { text: prompt, loading: false, visible: true } } : s));
    } catch (e) {
      setSegments(prev => prev.map(s => s.id === id ? { ...s, videoPrompt: { ...s.videoPrompt, loading: false } } : s));
    }
  };

  const handleBulkPrompt = async () => {
    for (const seg of segments) {
      if (seg.image.url && !seg.videoPrompt.text) await handleGenPrompt(seg.id);
    }
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("ZIP Lib error");
    const zip = new JSZip();
    let count = 0;
    for (let i = 0; i < segments.length; i++) {
      const seg = segments[i];
      if (seg.image?.url) {
        const base64Data = seg.image.url.split(',')[1];
        if (base64Data) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, base64Data, { base64: true }); count++; }
      }
    }
    if (count === 0) return alert("Không có ảnh.");
    const content = (await zip.generateAsync({ type: "blob" })) as any;
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `timelapse_images_${Date.now()}.zip`;
    link.click();
  };

  const progressSteps = getProgressArray(segments.length || sceneCount);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <input type="file" ref={segmentUploadRef} onChange={(e) => {
        const file = e.target.files?.[0];
        if (file && uploadingSegmentId !== null) {
          const reader = new FileReader();
          reader.onload = (ev) => setSegments(prev => prev.map(s => s.id === uploadingSegmentId ? { ...s, image: { ...s.image, url: ev.target?.result as string, loading: false } } : s));
          reader.readAsDataURL(file);
        }
        e.target.value = "";
      }} className="hidden" accept="image/*" />

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 p-8 mb-8">
        <div className="flex flex-col lg:flex-row gap-10">
          <div className="flex-1 space-y-6">
            <div className="flex justify-between items-center px-1">
                <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest">1. Ảnh tham chiếu</label>
                {context && (
                   <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-full uppercase">Loại dự án: {context.processType}</span>
                )}
            </div>
            <div className="grid grid-cols-2 gap-6">
                <div onClick={() => fileInputRef.current?.click()} className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group">
                    {basePreview ? <img src={basePreview} className="w-full h-full object-cover" /> : <span className="text-[10px] font-black uppercase text-slate-400">Ảnh Bắt Đầu</span>}
                    <input type="file" ref={fileInputRef} onChange={handleFileUpload} className="hidden" accept="image/*" />
                </div>
                <div onClick={() => finalInputRef.current?.click()} className="aspect-[3/4] border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-slate-50 cursor-pointer hover:border-orange-400 transition-all overflow-hidden relative group">
                    {finalPreview ? <img src={finalPreview} className="w-full h-full object-cover" /> : <span className="text-[10px] font-black uppercase text-slate-400">Ảnh Kết Thúc</span>}
                    <input type="file" ref={finalInputRef} onChange={handleFinalUpload} className="hidden" accept="image/*" />
                </div>
            </div>
          </div>

          <div className="flex-1 space-y-8">
            <div>
              <label className="block text-[11px] font-black text-slate-500 uppercase mb-4 tracking-widest px-1">2. Số lượng cảnh quay</label>
              <div className="grid grid-cols-3 gap-3">
                {DURATION_OPTIONS.map(opt => (
                  <button key={opt.scenes} onClick={() => setSceneCount(opt.scenes)} className={`p-4 rounded-xl text-[10px] font-black transition-all border-2 ${sceneCount === opt.scenes ? 'border-orange-500 bg-orange-50 text-orange-600' : 'border-slate-100 bg-slate-50 text-slate-400'}`}>{opt.label}</button>
                ))}
              </div>
            </div>
            <button onClick={handleStart} disabled={isProcessing || !basePreview || !finalPreview} className="w-full py-6 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:bg-black transition-all disabled:opacity-50 uppercase tracking-[0.2em] flex items-center justify-center gap-4">
              {isProcessing ? "ĐANG PHÂN TÍCH NGỮ CẢNH..." : "🚀 TẠO LỘ TRÌNH TIMELAPSE"}
            </button>
            {context && (
              <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl animate-fadeIn">
                 <h4 className="text-[10px] font-black text-blue-700 uppercase tracking-widest mb-2">Phân tích dự án:</h4>
                 <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-[8px] text-blue-400 font-bold uppercase">Chủ thể</p>
                      <p className="text-[10px] font-bold text-blue-900">{context.subject}</p>
                    </div>
                    <div>
                      <p className="text-[8px] text-blue-400 font-bold uppercase">Vật liệu thô</p>
                      <p className="text-[10px] font-bold text-blue-900">{context.rawMaterial}</p>
                    </div>
                 </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {segments.length > 0 && (
        <div className="space-y-12 pb-32">
          <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 shadow-2xl flex flex-col lg:flex-row items-center justify-between gap-6">
            <div>
                <h3 className="text-white font-black text-xl uppercase tracking-tight">Timeline Progress</h3>
                <p className="text-[10px] text-orange-500 font-bold uppercase tracking-widest mt-1">Sử dụng AI Phân tích ngữ cảnh đa năng</p>
            </div>
            <div className="flex flex-wrap gap-4">
              <button onClick={handleBulkImage} className="px-6 py-4 bg-orange-600 text-white text-[11px] font-black rounded-xl hover:bg-orange-700 transition-all uppercase flex items-center gap-2 shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4 3a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" clipRule="evenodd" /></svg>Vẽ ảnh tiến độ</button>
              <button onClick={handleBulkPrompt} className="px-6 py-4 bg-slate-700 text-white text-[11px] font-black rounded-xl hover:bg-slate-800 transition-all uppercase flex items-center gap-2 shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M13 10V3L4 14H11V21L20 10H13Z" /></svg>Tạo prompt video</button>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
            {segments.map((seg, idx) => {
              const progress = progressSteps[idx];
              return (
                <div key={seg.id} className="bg-white rounded-[2.5rem] border border-slate-200 shadow-sm overflow-hidden flex flex-col h-full group hover:shadow-xl transition-all">
                  <div className="relative aspect-[9/16] bg-slate-100 overflow-hidden">
                    {seg.image.url ? (
                      <img src={seg.image.url} className={`w-full h-full object-cover ${seg.image.loading ? 'blur-sm grayscale opacity-50' : ''}`} />
                    ) : (
                      <div className="absolute inset-0 flex flex-col items-center justify-center p-6 text-center">
                        {seg.image.loading ? (
                          <div className="w-10 h-10 border-4 border-orange-500 border-t-transparent rounded-full animate-spin"></div>
                        ) : (
                          <button onClick={() => handleGenImage(seg.id)} className="w-40 py-3 bg-[#f3591a] hover:bg-orange-700 text-white rounded-xl text-xs font-black shadow-lg uppercase">Vẽ ảnh {progress}%</button>
                        )}
                      </div>
                    )}
                    <div className="absolute top-4 left-4 bg-slate-900/80 backdrop-blur-md text-white text-[10px] font-black px-4 py-2 rounded-full shadow-lg">#{seg.id} • {progress}%</div>
                  </div>

                  <div className="p-6 space-y-4 flex flex-col flex-1">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Mô tả giai đoạn {progress}%:</label>
                      <textarea value={seg.content} onChange={e => setSegments(prev => prev.map(s => s.id === seg.id ? { ...s, content: e.target.value } : s))} className="w-full h-24 p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold text-slate-700 outline-none focus:bg-white resize-none shadow-inner" />
                    </div>
                    <div className="mt-auto grid grid-cols-2 gap-2">
                      <button onClick={() => handleGenImage(seg.id)} disabled={seg.image.loading} className="py-4 bg-slate-900 text-white text-[10px] font-black rounded-xl uppercase transition-all hover:bg-black">Vẽ ảnh</button>
                      <button onClick={() => handleGenPrompt(seg.id)} disabled={seg.videoPrompt.loading || !seg.image.url} className="py-4 bg-orange-50 text-orange-700 text-[10px] font-black rounded-xl uppercase transition-all border border-orange-100">Prompt</button>
                    </div>
                  </div>

                  {seg.videoPrompt.visible && (
                    <div className="p-5 bg-slate-900 border-t border-slate-800 animate-slideUp">
                      <div className="flex justify-between items-center mb-3">
                        <span className="text-[9px] font-black text-orange-500 uppercase tracking-widest">VEO-3 Prompt</span>
                        <button onClick={() => navigator.clipboard.writeText(seg.videoPrompt.text)} className="text-[9px] font-black text-white underline font-black">COPY</button>
                      </div>
                      <p className="text-[9px] text-slate-400 italic leading-snug">"{seg.videoPrompt.text}"</p>
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          <div className="flex flex-col md:flex-row items-center justify-center gap-6 py-12 border-t border-slate-200">
              <button onClick={downloadAllImages} className="w-full md:w-auto px-12 py-5 bg-slate-900 text-white font-black rounded-[2rem] shadow-xl hover:bg-black transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-base">Tải ZIP Ảnh</button>
              <button onClick={() => {
                const text = segments.map(seg => seg.videoPrompt?.text || "").filter(t => t.trim().length > 0).join('\n');
                const blob = new Blob([text], { type: 'text/plain' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = `timelapse_prompts_${Date.now()}.txt`;
                link.click();
              }} className="w-full md:w-auto px-12 py-5 bg-orange-600 text-white font-black rounded-[2rem] shadow-xl hover:bg-orange-700 transition-all flex items-center justify-center gap-3 uppercase tracking-widest text-base">Tải bộ Prompt</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default TimelapseModule;

