áp dụng các quy tắc dưới đây cho module timelapse:

import { GoogleGenAI, SchemaType } from "@google/genai";
import { getAiClient } from "./keyService";

// ============================================================================
// 1. DEFINITIONS & TYPES
// ============================================================================

export interface TimelapseContext {
  subject: string;
  processType: string;
  rawMaterial: string;
  toolsVisible: string;
}

// Định nghĩa kiểu cho phần dữ liệu ảnh gửi đi
export interface GenerativeImagePart {
  inlineData: {
    mimeType: string;
    data: string;
  }
}

const cleanJsonResponse = (text: string) => text.replace(/```json|```/g, "").trim();

export const fileToGenerativePart = async (file: File): Promise<GenerativeImagePart> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({
      inlineData: {
        mimeType: file.type,
        data: (reader.result as string).split(',')[1]
      }
    });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

// Hàm helper để chuyển base64 string thành object gửi cho AI (dùng cho ảnh previous)
export const base64ToGenerativePart = (base64String: string): GenerativeImagePart => {
    // Giả sử chuỗi dạng "data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAA..."
    const [prefix, data] = base64String.split(',');
    const mimeType = prefix.match(/:(.*?);/)?.[1] || 'image/png';
    return {
        inlineData: { mimeType, data }
    };
}

// ============================================================================
// 2. CORE FUNCTIONS
// ============================================================================

/**
 * BƯỚC 1: PHÂN TÍCH NGỮ CẢNH
 * (Giữ nguyên logic cũ vì đã hoạt động tốt)
 */
const analyzeTransformationContext = async (
  baseImagePart: GenerativeImagePart, 
  finalGoalPart: GenerativeImagePart
): Promise<TimelapseContext> => {
  const ai = getAiClient();
  const prompt = `
    ANALYZE transformation from Image A (Start) to Image B (End). Identify attributes in JSON:
    1. "subject": Main object?
    2. "processType": Process? (e.g., Construction, Art/Drawing, Biological Growth)
    3. "rawMaterial": 0-10% stage look?
    4. "toolsVisible": Tools seen?
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: { 
        parts: [{ text: prompt }, baseImagePart, finalGoalPart] 
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: SchemaType.OBJECT,
          properties: {
            subject: { type: SchemaType.STRING },
            processType: { type: SchemaType.STRING },
            rawMaterial: { type: SchemaType.STRING },
            toolsVisible: { type: SchemaType.STRING },
          },
          required: ["subject", "processType", "rawMaterial", "toolsVisible"]
        }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (error) {
    return { subject: "Object", processType: "Construction", rawMaterial: "Unfinished", toolsVisible: "Tools" };
  }
};

/**
 * BƯỚC 2: TẠO KỊCH BẢN
 * (Giữ nguyên logic cũ)
 */
export const generateTimelapseScript = async (
  baseImagePart: GenerativeImagePart, 
  finalGoalPart: GenerativeImagePart, 
  sceneCount: number,
  progressSteps: number[]
): Promise<{ script: string[], context: TimelapseContext }> => {
  const context = await analyzeTransformationContext(baseImagePart, finalGoalPart);
  const ai = getAiClient();
  const prompt = `
    CONTEXT: Subject: ${context.subject}, Process: ${context.processType}, Raw: ${context.rawMaterial}.
    TASK: Generate ${sceneCount}-step Vietnamese description for timelapse stages: ${progressSteps.join('%, ')}%.
    RULES: Adapt strictly to "${context.processType}". Early stages focus on raw material. Middle on active work/tools. Late on finishing.
    OUTPUT: JSON Array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: { parts: [{ text: prompt }] },
      config: { responseMimeType: "application/json", responseSchema: { type: SchemaType.ARRAY, items: { type: SchemaType.STRING } } }
    });
    return { script: JSON.parse(cleanJsonResponse(response.text || '[]')), context };
  } catch (error) {
    return { script: progressSteps.map(p => `Giai đoạn ${p}%...`), context };
  }
};

/**
 * BƯỚC 3 (NÂNG CẤP QUAN TRỌNG): TẠO ẢNH TRUNG GIAN VỚI TÍNH LIÊN TỤC VÀ LUẬT CẤM
 */
export const generateTimelapseImage = async (
  context: TimelapseContext,
  sceneDescription: string,
  baseImagePart: GenerativeImagePart,
  finalGoalPart: GenerativeImagePart,
  progress: number,
  // THAM SỐ MỚI: Ảnh được tạo ra ở bước trước đó (nếu có)
  previousImagePart: GenerativeImagePart | null 
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.0-flash-exp"; 

  const process = context.processType.toLowerCase();
  const isConstruction = ["construction", "renovation", "interior", "decor"].some(k => process.includes(k));

  // --- LOGIC 1: XÁC ĐỊNH "SỰ BỪA BỘN" ---
  let messDescription = "";
  if (isConstruction) {
     messDescription = "Construction site atmosphere: Dust, debris, paint buckets, ladders. Furniture wrapped in blue plastic sheets.";
  } else if (process.includes("art")) {
     messDescription = "Artist workspace: Pencil shavings, paint spills, palettes. Artwork looks half-finished.";
  } else if (process.includes("nature")) {
     messDescription = "Nature atmosphere: Soil, leaves, water droplets. Organic growth texture.";
  }

  // --- LOGIC 2: LUẬT CẤM TUYỆT ĐỐI CHO NỘI THẤT < 80% ---
  let negativeConstraints = "";
  if (isConstruction && progress < 80) {
      negativeConstraints = `
      CRITICAL NEGATIVE CONSTRAINTS (ABSOLUTELY FORBIDDEN):
      - NO mattresses, bedding, or pillows on beds (beds must be bare frames or wrapped).
      - NO table lamps, floor lamps, or ceiling lights turned on.
      - NO computer towers, laptops, keyboards, or monitors (screens must be black/off or missing).
      - NO wall art, picture frames, or decorative hangings.
      - These items MUST NOT appear or must look like empty spaces/sockets.
      `;
  }

  // --- LOGIC 3: TÍNH LIÊN TỤC (VISUAL CONTINUITY) ---
  let continuityInstruction = "";
  if (previousImagePart) {
      continuityInstruction = `
      VISUAL CONTINUITY REFERENCE:
      - Use the provided "Previous Frame Image" as the direct starting point.
      - The new image MUST show the evolution FROM the previous state.
      - Maintain the exact shape and form of objects established in the previous frame.
      `;
  }

  // --- TẠO PROMPT KỸ THUẬT ---
  const prompt = `
    ROLE: Time-lapse Visual Artist. TASK: Generate intermediate frame at ${progress}%.
    CONTEXT: ${context.processType} of ${context.subject}.

    VISUAL RULES:
    1. STAGE < 25%: Dominance of "${context.rawMaterial}".
    2. STAGE 25-85%: THE "UGLY" PHASE. Show ${messDescription}. "${context.toolsVisible}" interacting.
    3. STAGE > 85%: Cleaning up. Polishing phase.

    ${negativeConstraints}

    ${continuityInstruction}

    CONSTRAINT: Keep Perspective IDENTICAL to Goal Image. Photorealistic.
    SCENE: "${sceneDescription}"
  `;

  // --- CHIẾN THUẬT GỬI ẢNH INPUT ---
  let contents: any[] = [{ text: prompt }];

  // Luôn gửi Goal Image để giữ khung
  contents.push(finalGoalPart);

  if (progress < 25 && !previousImagePart) {
      // Giai đoạn đầu tiên: Gửi thêm Base Image để lấy nền móng
      contents.push(baseImagePart);
  } else if (previousImagePart) {
      // Các giai đoạn sau: Gửi thêm Previous Image để giữ tính liên tục
      // Đặt previous lên trước goal để ưu tiên tính liên tục của quá trình
      contents.unshift(previousImagePart); 
  }

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("No image generated");
    return `data:${imgPart.inlineData.mimeType};base64,${imgPart.inlineData.data}`;
  } catch (error) {
    console.error("Image Gen Error:", error);
    throw error;
  }
};

/**
 * BƯỚC 4 (NÂNG CẤP): VIDEO PROMPT NHẬN DIỆN CHUYỂN ĐỘNG TỪ ẢNH TRƯỚC
 */
export const generateTimelapseVideoPrompt = async (
  context: TimelapseContext,
  description: string,
  currentImageBase64: string, // Ảnh hiện tại
  progress: number,
  // THAM SỐ MỚI: Ảnh trước đó để mô tả chuyển động
  previousImagePart: GenerativeImagePart | null
): Promise<string> => {
  const ai = getAiClient();
  const process = context.processType.toLowerCase();

  let actionPrompt = "";
  // (Logic chọn hành động dựa trên context - giữ nguyên như trước)
  if (["construction", "renovation", "interior"].some(k => process.includes(k))) {
      actionPrompt = progress < 90 ? "Include 1 worker moving tools/materials. Fast-forward style." : "Cinematic slow pan revealing finished room. No people.";
  } else if (["drawing", "art", "sketch"].some(k => process.includes(k))) {
      actionPrompt = `Close-up. Hand holding ${context.toolsVisible} actively working. Fast strokes.`;
  } else if (["plant", "nature"].some(k => process.includes(k))) {
      actionPrompt = "Organic growth. Object pulsing slightly. Shadows moving quickly.";
  } else {
      actionPrompt = "Time-lapse movement. Lighting shifts. Objects evolve naturally.";
  }

  // Prompt mô tả sự thay đổi
  let transitionPrompt = "";
  if (previousImagePart) {
      transitionPrompt = "ACTION FOCUS: Describe the visual transition and movement evolving FROM the state in the 'Previous Image' TO the state in the 'Current Image'.";
  }

  const prompt = `
    Generate VEO-3 video prompt (English).
    SCENE: ${description}. CONTEXT: ${context.processType}. PROGRESS: ${progress}%.
    MANDATORY ACTION: ${actionPrompt}
    ${transitionPrompt}
    STYLE: 4K, 60fps, Photorealistic. OUTPUT: Raw prompt string only.
  `;

  const contents: any[] = [{ text: prompt }];
  // Gửi ảnh hiện tại (Bắt buộc)
  contents.push(base64ToGenerativePart(currentImageBase64));
  // Gửi ảnh trước đó (Nếu có, để AI hiểu sự thay đổi)
  if (previousImagePart) {
      contents.push(previousImagePart);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.0-flash",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) {
    return `Timelapse video of ${context.subject}, ${progress}%.`;
  }
};

