  sceneDescription: string,
  baseImagePart: GenerativeImagePart,
  finalGoalPart: GenerativeImagePart,
  progress: number,
  previousImagePart: GenerativeImagePart | null
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";

  let specificVisualConstraint = "";

  if (progress <= 25) {
      // Giai đoạn 20%: Hoàn thiện bề mặt, không đồ đạc
      specificVisualConstraint = `
      PHASE STATUS: SURFACES FINISHED.
      - WALLS: Perfectly painted or wallpapered as in the Goal Image.
      - FLOOR: Flooring material (tiles/wood) is fully laid and clean.
      - DOORS/WINDOWS: Installed and finished.
      - FURNITURE: ABSOLUTELY NO FURNITURE. The room must be EMPTY.
      `;
  } else if (progress > 25 && progress <= 65) {
      // Giai đoạn 30% - 60%: Chuyển đồ, bọc nilon, thùng carton
      specificVisualConstraint = `
      PHASE STATUS: MOVING IN & PROTECTED.
      - MESSY ENVIRONMENT: Furniture items are scattered and NOT in their final positions.
      - PACKAGING: Most large furniture pieces MUST be wrapped in blue or transparent plastic nylon sheets. 
      - BOXES: Several brown cardboard boxes of various sizes are on the floor.
      - DISORDER: Items are disorganized as if just unloaded from a truck.
      `;
  } else {
      // Giai đoạn hoàn thiện
      specificVisualConstraint = `
      PHASE STATUS: REFINING.
      - Furniture is mostly unpacked and moved to correct positions.
      - Only a few protective sheets or empty boxes remain.
      `;
  }

  const prompt = `
    TASK: Generate an intermediate timelapse frame at ${progress}% for "${context.subject}".
    ${specificVisualConstraint}

    VISUAL CONTINUITY:
    - Use the provided Goal Image to ensure the architecture (windows, lights, walls) matches 100%.
    - Maintain the exact camera angle of the Goal Image.
    ${previousImagePart ? "- Evolve directly from the state shown in the Previous Image." : ""}

    SCENE DESCRIPTION: "${sceneDescription}"
    STYLE: Photorealistic, 8k, professional commercial shot. No text, no logos.
  `;

  let contents: any[] = [{ text: prompt }, finalGoalPart];
  if (previousImagePart) contents.push(previousImagePart);
  if (progress < 25) contents.push(baseImagePart);

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });

    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    if (!imgPart) throw new Error("No image generated.");
    return `data:image/png;base64,${imgPart.inlineData.data}`;
  } catch (error) {
    throw error;
  }
};

