  } else {
      compositionInstruction = "COMPOSITION: FILL THE ENTIRE 3:4 FRAME. FULL BLEED. Subject centered vertically. ENSURE TOP 25% AND BOTTOM 25% are CLEAR BACKGROUND areas.";
