const cleanJsonResponse = (text: string) => {
  return text.replace(/```json|```/g, "").trim();
};

export const fileToGenerativePart = async (file: File) => {
  return new Promise<{ mimeType: string, data: string }>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve({ mimeType: file.type, data: (reader.result as string).split(',')[1] });
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

const FORBIDDEN_TERMS = `Facebook, Shopee, Lazada, Tiki, Zalo, Sale sốc, Mua ngay, Cam kết, Top 1, Giá rẻ nhất, duy nhất, tri ân.`;

/**
 * Lấy hướng dẫn chi tiết về giọng đọc dựa trên nhãn lựa chọn.
 */
const getVoiceDetailedInstruction = (voiceLabel: string) => {
  const isNorth = voiceLabel.includes("Bắc");

  const dialectInstruction = isNorth ? `
    VĂN PHONG MIỀN BẮC (HÀ NỘI):
    - Sử dụng từ đệm: "nhé", "ạ", "thế", "đấy", "vậy", "vâng", "chứ".
    - Cách dùng từ: "không", "vẫn", "thế này".
    - TUYỆT ĐỐI KHÔNG dùng các từ miền Nam như: nha, nè, nghen, thiệt, hông, vầy, bển, trển.
  ` : `
    VĂN PHONG MIỀN NAM (SÀI GÒN):
    - Sử dụng từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy", "nghen", "ha".
    - Cách dùng từ: "hông" (thay cho không), "thiệt" (thay cho thật), "dễ thương dữ thần", "hết sảy".
    - TUYỆT ĐỐI KHÔNG dùng các từ miền Bắc như: nhé, ạ, thế, đấy, chả, vâng.
  `;

  const mapping: Record<string, string> = {
    "Giọng Bắc 20-40 tuổi": "20-40 tuổi, giọng miền Bắc, năng động, nhịp độ nhanh, vui vẻ, tông cao, hào hứng.",
    "Giọng Nam 20-40 tuổi": "20-40 tuổi, giọng miền Nam, năng động, nhịp độ nhanh, vui vẻ, tông cao, hào hứng.",
    "Giọng Bắc 50-60 tuổi": "50-60 tuổi, giọng miền Bắc, giọng trầm, vang, ổn định, uy quyền, đáng tin cậy.",
    "Giọng Nam 50-60 tuổi": "50-60 tuổi, giọng miền Nam, giọng trầm, vang, ổn định, uy quyền, đáng tin cậy.",
    "Giọng Bắc 60-80 tuổi": "60-80 tuổi, giọng miền Bắc, khàn, hào sảng, chân chất, thực tế.",
    "Giọng Nam 60-80 tuổi": "60-80 tuổi, giọng miền Nam, khàn, hào sảng, chân chất, thực tế."
  };

  return (mapping[voiceLabel] || voiceLabel) + "\n" + dialectInstruction;
};

export const generatePersonificationScript = async (
  healthKeyword: string,
  ctaProduct: string,
  frameCount: number,
  gender: string,
  voice: string,
  addressing: string,
  style: string,
  characterDescription: string
): Promise<string[]> => {
  const ai = getAiClient();
  const voiceDetail = getVoiceDetailedInstruction(voice);

  const prompt = `
    Nhiệm vụ: Tạo kịch bản TikTok nhân hóa bộ phận cơ thể hoặc vật thể dựa trên NỘI DUNG NGUỒN.
    NỘI DUNG NGUỒN: "${healthKeyword}"
    SẢN PHẨM CTA: "${ctaProduct}"
    SỐ KHUNG HÌNH: ${frameCount}

    NHÂN VẬT: Giới tính ${gender}, Đặc điểm giọng nói & Văn phong: ${voiceDetail}.
    MÔ TẢ NGOẠI HÌNH NHÂN VẬT: "${characterDescription}"
    PHONG CÁCH KỊCH BẢN: "${style}".

    HƯỚNG DẪN XỬ LÝ:
    1. Phân tích nội dung nguồn để tìm ra nhân vật nhân hóa liên quan nhất (VD: gan, tim, phổi, mắt, củ khoai tây, cây súp lơ...).
    2. Tạo kịch bản từ góc nhìn bộ phận đó đang "tâm sự", "mắng" hoặc "chia sẻ" với chủ nhân.
    3. XƯNG HÔ (BẮT BUỘC): Sử dụng cặp xưng hô "${addressing}" (Người nói - Người nghe) xuyên suốt 100%.

    !!! QUY TẮC ĐỘ DÀI NGHIÊM NGẶT !!!:
    - Mỗi đoạn kịch bản BẮT BUỘC có độ dài từ 160 đến 190 ký tự.
    - Tuyệt đối không được ngắn hơn 160 ký tự.

    YÊU CẦU NGÔN NGỮ: Tuân thủ quy tắc văn phong vùng miền: ${voiceDetail}.
    Trả về mảng JSON các chuỗi ký tự.
    TUYỆT ĐỐI KHÔNG DÙNG TỪ CẤM: ${FORBIDDEN_TERMS}
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Script generation failed", e);
    return [];
  }
};

export const generatePersonificationImage = async (
  script: string,
  productImages: any[],
  characterPart: any | null,
  healthKeyword: string,
  ctaProduct: string,
  gender: string,
  globalCharDesc: string,
  sceneIdea: string,
  regenNote: string = ""
): Promise<string> => {
  const ai = getAiClient();

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = (regenNote + sceneIdea).toLowerCase().split(' ').some(word => noProductKeywords.includes(word));

  const visualRules = `
    CRITICAL VISUAL RULES (STRICT NO-TEXT POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. The background must be CLEAN and FREE of signage, posters, labels, or written words.
    3. If the context implies a screen or sign, leave it BLANK or Abstract.
    4. NO UI elements, NO speech bubbles, NO watermarks, NO subtitles.
    5. The image must be purely visual storytelling.
    6. ABSOLUTELY NO ICONS, NO GRAPHICS, NO EMOJIS, NO VISUAL EFFECTS, NO OVERLAYS.
    7. Do NOT simulate TikTok UI or video editing effects. It must look like a RAW 3D RENDER.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. 
    2. Must look like high-quality 3D Animation Pixar/Disney style, vibrant colors, polished CGI, masterpiece.

    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT/DEVICE IN THIS IMAGE.' : `
    3. STRICT PRODUCT FIDELITY (MANDATORY - TUYỆT ĐỐI):
       - The product "${ctaProduct}" MUST MATCH the input reference images provided.
       - PRESERVE PATTERNS & TEXTURES: Any pattern (họa tiết), logo, or design on the product surface must be preserved.
       - PRESERVE DIMENSIONS: Do not resize or distort the product logic.
       - CONSISTENT SCALE: Đảm bảo kích thước và tỷ lệ của sản phẩm phải đồng nhất.
       - LOCK the product appearance exactly to the original photos provided 1:1.`}
  `;

  const characterFidelity = characterPart 
    ? `CHARACTER REFERENCE: You MUST use the EXACT character design from the CHARACTER_REFERENCE image. Maintain 1:1 identity consistency.`
    : `CHARACTER IDENTITY: A personified character based on: "${healthKeyword.substring(0, 100)}". Gender traits: ${gender}. Appearance: ${globalCharDesc}`;

  const prompt = `
    Style: 3D Animation Pixar style, vibrant colors, polished CGI, masterpiece. 
    Aspect ratio 9:16.

    ${characterFidelity}

    !!! SPECIFIC SCENE IDEA: "${sceneIdea}" !!!
    Action description: "${script}".

    The character must have a cute/funny/sassy expressive face, arms, legs, and a moving mouth.
    Setting: Based on scene idea: "${sceneIdea}".

    ${visualRules}
    ${regenNote ? `Additional Feedback: ${regenNote}` : ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (characterPart) contents.push({ inlineData: characterPart });
  if (!isNoProductRequested) productImages.forEach(img => contents.push({ inlineData: img }));

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (e) {
    throw e;
  }
};

export const generatePersonificationVeoPrompt = async (
  script: string,
  healthKeyword: string,
  gender: string,
  voice: string,
  style: string,
  globalDesc: string,
